		private readonly List<VersionInfo> m_VersionChanges = new List<VersionInfo>();

		private readonly HashSet<object> m_TrackedObjects = new HashSet<object>();

		private readonly HashSet<Binding> m_RanUpdate = new HashSet<Binding>();

		private readonly HashSet<object> m_KnownSources = new HashSet<object>();

		private readonly HashSet<Binding> m_DirtyBindings = new HashSet<Binding>();

		private BaseVisualElementPanel m_AttachedPanel;

		private DataBindingManager bindingManager => base.panel.dataBindingManager;

		public override ProfilerMarker profilerMarker => s_UpdateProfilerMarker;

		public VisualTreeDataBindingsUpdater()
		{
			base.panelChanged += OnPanelChanged;
		}

		protected void OnHierarchyChange(VisualElement ve, HierarchyChangeType type, IReadOnlyList<VisualElement> additionalContext = null)
		{
			if (bindingManager.GetBoundElementsCount() == 0 && bindingManager.GetTrackedDataSourcesCount() == 0)
			{
				return;
			}
			switch (type)
			{
			case HierarchyChangeType.RemovedFromParent:
				m_DataSourceChangedRequests.Remove(ve);
				m_RemovedElements.Add(ve);
				break;
			case HierarchyChangeType.AddedToParent:
			case HierarchyChangeType.ChildrenReordered:
				m_RemovedElements.Remove(ve);
				m_DataSourceChangedRequests.Add(ve);
				break;
			case HierarchyChangeType.AttachedToPanel:
			{
				for (int j = 0; j < additionalContext.Count; j++)
				{
					VisualElement item2 = additionalContext[j];
					m_RemovedElements.Remove(item2);
					m_DataSourceChangedRequests.Add(ve);
				}
				break;
			}
			case HierarchyChangeType.DetachedFromPanel:
			{
				for (int i = 0; i < additionalContext.Count; i++)
				{
					VisualElement item = additionalContext[i];
					m_DataSourceChangedRequests.Remove(ve);
					m_RemovedElements.Add(item);
				}
				break;
			}
			}
			bindingManager.DirtyBindingOrder();
		}

		public override void OnVersionChanged(VisualElement ve, VersionChangeType versionChangeType)
		{
			if ((versionChangeType & VersionChangeType.BindingRegistration) == VersionChangeType.BindingRegistration)
			{
				m_BindingRegistrationRequests.Add(ve);
			}
			if ((versionChangeType & VersionChangeType.DataSource) == VersionChangeType.DataSource)
			{
				m_DataSourceChangedRequests.Add(ve);
			}
		}

		private void CacheAndLogBindingResult(bool appliedOnUiCache, in DataBindingManager.BindingData bindingData, in BindingResult result)
		{
			switch (bindingManager.logLevel)
			{
			case BindingLogLevel.Once:
			{
				BindingResult result2;
				if (appliedOnUiCache)
				{
					bindingManager.TryGetLastUIBindingResult(bindingData, out result2);
				}
				else
				{
					bindingManager.TryGetLastSourceBindingResult(bindingData, out result2);
				}
				if (result2.status != result.status || result2.message != result.message)
				{
					LogResult(in result);
				}
				break;
			}
			default:
				LogResult(in result);
				break;
			case BindingLogLevel.None:
				break;
			}
			if (appliedOnUiCache)
			{
				bindingManager.CacheUIBindingResult(bindingData, result);
			}
			else
			{
				bindingManager.CacheSourceBindingResult(bindingData, result);
			}
		}

		private void LogResult(in BindingResult result)
		{
			if (!string.IsNullOrWhiteSpace(result.message))
			{
				string text = (base.panel as Panel)?.name ?? base.panel.visualTree.name;
				Debug.LogWarning(result.message + " (" + text + ")");
			}
		}

		public override void Update()
		{
			ProcessAllBindingRequests();
			ProcessDataSourceChangedRequests();
			ProcessPropertyChangedEvents(m_RanUpdate);
			m_BoundsElement.AddRange(bindingManager.GetBoundElements());
			foreach (VisualElement item in m_BoundsElement)
			{
				List<DataBindingManager.BindingData> bindingData = bindingManager.GetBindingData(item);
				for (int i = 0; i < bindingData.Count; i++)
				{
					DataBindingManager.BindingData bindingData2 = bindingData[i];
					object dataSource;
					PropertyPath path;
					using (s_ShouldUpdateBindingProfilerMarker.Auto())
					{
						DataSourceContext resolvedDataSourceContext = bindingManager.GetResolvedDataSourceContext(item, bindingData2);
						dataSource = resolvedDataSourceContext.dataSource;
						path = resolvedDataSourceContext.dataSourcePath;
						var (flag, version) = GetDataSourceVersion(dataSource);
						if (bindingData2.binding == null)
						{
							continue;
						}
						if (dataSource != null && m_TrackedObjects.Add(dataSource))
						{
							m_VersionChanges.Add(new VersionInfo(dataSource, version));
						}
						if (bindingData2.binding.isDirty)
						{
							m_DirtyBindings.Add(bindingData2.binding);
						}
						if (!m_Updater.ShouldProcessBindingAtStage(bindingData2.binding, BindingUpdateStage.UpdateUI, flag, m_DirtyBindings.Contains(bindingData2.binding)))
						{
							continue;
						}
						if (dataSource != null && flag)
						{
							m_KnownSources.Add(dataSource);
						}
						if (bindingData2.binding.updateTrigger == BindingUpdateTrigger.OnSourceChanged && dataSource is INotifyBindablePropertyChanged && !bindingData2.binding.isDirty)
						{
							HashSet<PropertyPath> changedDetectedFromSource = bindingManager.GetChangedDetectedFromSource(dataSource);
							if (changedDetectedFromSource == null || changedDetectedFromSource.Count == 0)
							{
								continue;
							}
							bool flag2 = path.IsEmpty;
							foreach (PropertyPath item2 in changedDetectedFromSource)
							{
								if (IsPrefix(item2, in path))
								{
									flag2 = true;
									break;
								}
							}
							if (!flag2)
							{
								continue;
							}
							goto IL_0242;
						}
						goto IL_0242;
					}
					IL_0242:
					bool isDirty = bindingData2.binding.isDirty;
					bindingData2.binding.ClearDirty();
					BindingContext context = new BindingContext(item, in bindingData2.target.bindingId, in path, dataSource);
					BindingResult result = default(BindingResult);
					long version2 = bindingData2.version;
					using (s_UpdateBindingProfilerMarker.Auto())
					{
						result = m_Updater.UpdateUI(in context, bindingData2.binding);
					}
					CacheAndLogBindingResult(appliedOnUiCache: true, in bindingData2, in result);
					if (bindingData2.version != version2)
					{
						continue;
					}
					switch (result.status)
					{
					case BindingStatus.Success:
						m_RanUpdate.Add(bindingData2.binding);
						break;
					case BindingStatus.Pending:
						if (isDirty)
						{
							bindingData2.binding.MarkDirty();
						}
						break;
					}
				}
			}
			foreach (VersionInfo versionChange in m_VersionChanges)
			{
				bindingManager.UpdateVersion(versionChange.source, versionChange.version);
			}
			ProcessPropertyChangedEvents(m_RanUpdate);
			foreach (object knownSource in m_KnownSources)
			{
				bindingManager.ClearChangesFromSource(knownSource);
			}
			m_BoundsElement.Clear();
			m_VersionChanges.Clear();
			m_TrackedObjects.Clear();
			m_RanUpdate.Clear();
			m_KnownSources.Clear();
			m_DirtyBindings.Clear();
			bindingManager.ClearSourceCache();
		}

		private (bool changed, long version) GetDataSourceVersion(object source)
		{
			if (bindingManager.TryGetLastVersion(source, out var version))
			{
				if (!(source is IDataSourceViewHashProvider dataSourceViewHashProvider))
				{
					return (changed: source != null, version: version + 1);
				}
				long viewHashCode = dataSourceViewHashProvider.GetViewHashCode();
				return (viewHashCode == version) ? (changed: false, version: version) : (changed: true, version: viewHashCode);
			}
			if (source is IDataSourceViewHashProvider dataSourceViewHashProvider2)
			{
				return (changed: true, version: dataSourceViewHashProvider2.GetViewHashCode());
			}
			return (changed: source != null, version: 0L);
		}

		private bool IsPrefix(in PropertyPath prefix, in PropertyPath path)
		{
			if (path.Length < prefix.Length)
			{
				return false;
			}
			for (int i = 0; i < prefix.Length; i++)
			{
				PropertyPathPart propertyPathPart = prefix[i];
				PropertyPathPart propertyPathPart2 = path[i];
				if (propertyPathPart.Kind != propertyPathPart2.Kind)
				{
					return false;
				}
				switch (propertyPathPart.Kind)
				{
				case PropertyPathPartKind.Name:
					if (propertyPathPart.Name != propertyPathPart2.Name)
					{
						return false;
					}
					break;
				case PropertyPathPartKind.Index:
					if (propertyPathPart.Index != propertyPathPart2.Index)
					{
						return false;
					}
					break;
				case PropertyPathPartKind.Key:
					if (propertyPathPart.Key != propertyPathPart2.Key)
					{
						return false;
					}
					break;
				default:
					throw new ArgumentOutOfRangeException();
				}
			}
			return true;
		}

		private void ProcessDataSourceChangedRequests()
		{
			using (s_ProcessDataSourcesProfilerMarker.Auto())
			{
				if (m_DataSourceChangedRequests.Count != 0 || m_RemovedElements.Count != 0)
				{
					m_DataSourceChangedRequests.RemoveWhere((VisualElement e) => e.panel == null);
					bindingManager.InvalidateCachedDataSource(m_DataSourceChangedRequests, m_RemovedElements);
					m_DataSourceChangedRequests.Clear();
					m_RemovedElements.Clear();
				}
			}
		}

		private void OnPanelChanged(BaseVisualElementPanel p)
		{
			if (m_AttachedPanel != p)
			{
				if (m_AttachedPanel != null)
				{
					m_AttachedPanel.hierarchyChanged -= OnHierarchyChange;
				}
				m_AttachedPanel = p;
				if (m_AttachedPanel != null)
				{
					m_AttachedPanel.hierarchyChanged += OnHierarchyChange;
				}
			}
		}

		protected override void Dispose(bool disposing)
		{
			ProcessAllBindingRequests();
			ProcessDataSourceChangedRequests();
			base.Dispose(disposing);
			bindingManager.Dispose();
		}

		private void ProcessAllBindingRequests()
		{
			using (s_ProcessBindingRequestsProfilerMarker.Auto())
			{
				for (int i = 0; i < m_BindingRegistrationRequests.Count; i++)
				{
					VisualElement visualElement = m_BindingRegistrationRequests[i];
					if (visualElement.panel == base.panel)
					{
						ProcessBindingRequests(visualElement);
					}
				}
				m_BindingRegistrationRequests.Clear();
			}
		}

		private void ProcessBindingRequests(VisualElement element)
		{
			bindingManager.ProcessBindingRequests(element);
		}

		private void ProcessPropertyChangedEvents(HashSet<Binding> ranUpdate)
		{
			List<DataBindingManager.ChangesFromUI> changedDetectedFromUI = bindingManager.GetChangedDetectedFromUI();
			for (int i = 0; i < changedDetectedFromUI.Count; i++)
			{
				DataBindingManager.ChangesFromUI changesFromUI = changedDetectedFromUI[i];
				if (!changesFromUI.IsValid)
				{
					continue;
				}
				DataBindingManager.BindingData bindingData = changesFromUI.bindingData;
				Binding binding = bindingData.binding;
				VisualElement element = bindingData.target.element;
				if (!m_Updater.ShouldProcessBindingAtStage(binding, BindingUpdateStage.UpdateSource, versionChanged: true, dirty: false) || ranUpdate.Contains(binding))
				{
					continue;
				}
				DataSourceContext resolvedDataSourceContext = bindingManager.GetResolvedDataSourceContext(bindingData.target.element, bindingData);
				object dataSource = resolvedDataSourceContext.dataSource;
				PropertyPath resolvedDataSourcePath = resolvedDataSourceContext.dataSourcePath;
				BindingContext context = new BindingContext(element, in bindingData.target.bindingId, in resolvedDataSourcePath, dataSource);
				BindingResult result = m_Updater.UpdateSource(in context, binding);
				CacheAndLogBindingResult(appliedOnUiCache: false, in bindingData, in result);
				if (result.status != BindingStatus.Success || !changesFromUI.IsValid)
				{
					continue;
				}
				bool isDirty = bindingData.binding.isDirty;
				bindingData.binding.ClearDirty();
				BindingContext context2 = new BindingContext(element, in bindingData.target.bindingId, in resolvedDataSourcePath, dataSource);
				using (bindingManager.IgnoreChangesScope(element, context2.bindingId, binding))
				{
					result = m_Updater.UpdateUI(in context2, binding);
					CacheAndLogBindingResult(appliedOnUiCache: true, in bindingData, in result);
				}
				if (result.status == BindingStatus.Pending)
				{
					if (isDirty)
					{
						bindingData.binding.MarkDirty();
					}
					else
					{
						bindingData.binding.ClearDirty();
					}
				}
			}
			changedDetectedFromUI.Clear();
		}

		internal void PollElementsWithBindings(Action<VisualElement, IBinding> callback)
		{
			if (bindingManager.GetBoundElementsCount() <= 0)
			{
				return;
			}
			foreach (VisualElement unorderedBoundElement in bindingManager.GetUnorderedBoundElements())
			{
				if (unorderedBoundElement.elementPanel == base.panel)
				{
					callback(unorderedBoundElement, null);
				}
			}
		}
	}
	internal class ClampedDragger<T> : Clickable where T : IComparable<T>
	{
		[Flags]
		public enum DragDirection
		{
			None = 0,
			LowToHigh = 1,
			HighToLow = 2,
			Free = 4
		}

		public DragDirection dragDirection { get; set; }

		private BaseSlider<T> slider { get; set; }

		public Vector2 startMousePosition { get; private set; }

		public Vector2 delta => base.lastMousePosition - startMousePosition;

		public event Action dragging;

		public event Action draggingEnded;

		public ClampedDragger(BaseSlider<T> slider, Action clickHandler, Action dragHandler)
			: base(clickHandler, 250L, 30L)
		{
			dragDirection = DragDirection.None;
			this.slider = slider;
			dragging += dragHandler;
		}

		protected override void ProcessDownEvent(EventBase evt, Vector2 localPosition, int pointerId)
		{
			startMousePosition = localPosition;
			dragDirection = DragDirection.None;
			base.ProcessDownEvent(evt, localPosition, pointerId);
			this.dragging?.Invoke();
		}

		protected override void ProcessUpEvent(EventBase evt, Vector2 localPosition, int pointerId)
		{
			base.ProcessUpEvent(evt, localPosition, pointerId);
			this.draggingEnded?.Invoke();
		}

		protected override void ProcessMoveEvent(EventBase evt, Vector2 localPosition)
		{
			base.ProcessMoveEvent(evt, localPosition);
			if (dragDirection == DragDirection.None)
			{
				dragDirection = DragDirection.Free;
			}
			if (dragDirection != DragDirection.Free)
			{
				return;
			}
			if (evt.eventTypeId == EventBase<PointerMoveEvent>.TypeId())
			{
				PointerMoveEvent pointerMoveEvent = (PointerMoveEvent)evt;
				if (pointerMoveEvent.pointerId != PointerId.mousePointerId)
				{
					pointerMoveEvent.isHandledByDraggable = true;
				}
			}
			this.dragging?.Invoke();
		}
	}
	public class Clickable : PointerManipulator
	{
		private readonly long m_Delay;

		private readonly long m_Interval;

		private int m_ActivePointerId = -1;

		private bool m_AcceptClicksIfDisabled;

		private IVisualElementScheduledItem m_Repeater;

		private IVisualElementScheduledItem m_PendingActivePseudoStateReset;

		protected bool active { get; set; }

		public Vector2 lastMousePosition { get; private set; }

		internal bool acceptClicksIfDisabled
		{
			get
			{
				return m_AcceptClicksIfDisabled;
			}
			set
			{
				if (m_AcceptClicksIfDisabled != value)
				{
					if (base.target != null)
					{
						UnregisterCallbacksFromTarget();
					}
					m_AcceptClicksIfDisabled = value;
					if (base.target != null)
					{
						RegisterCallbacksOnTarget();
					}
				}
			}
		}

		private InvokePolicy invokePolicy => acceptClicksIfDisabled ? InvokePolicy.IncludeDisabled : InvokePolicy.Default;

		public event Action<EventBase> clickedWithEventInfo;

		public event Action clicked;

		public Clickable(Action handler, long delay, long interval)
			: this(handler)
		{
			m_Delay = delay;
			m_Interval = interval;
			active = false;
		}

		public Clickable(Action<EventBase> handler)
		{
			this.clickedWithEventInfo = handler;
			base.activators.Add(new ManipulatorActivationFilter
			{
				button = MouseButton.LeftMouse
			});
		}

		public Clickable(Action handler)
		{
			this.clicked = handler;
			base.activators.Add(new ManipulatorActivationFilter
			{
				button = MouseButton.LeftMouse
			});
			active = false;
		}

		private void OnTimer(TimerState timerState)
		{
			if ((this.clicked != null || this.clickedWithEventInfo != null) && IsRepeatable())
			{
				if (ContainsPointer(m_ActivePointerId) && (base.target.enabledInHierarchy || acceptClicksIfDisabled))
				{
					Invoke(null);
					base.target.pseudoStates |= PseudoStates.Active;
				}
				else
				{
					base.target.pseudoStates &= ~PseudoStates.Active;
				}
			}
		}

		private bool IsRepeatable()
		{
			return m_Delay > 0 || m_Interval > 0;
		}

		protected override void RegisterCallbacksOnTarget()
		{
			base.target.RegisterCallback<PointerDownEvent>(OnPointerDown, invokePolicy);
			base.target.RegisterCallback<PointerMoveEvent>(OnPointerMove, invokePolicy);
			base.target.RegisterCallback<PointerUpEvent>(OnPointerUp, InvokePolicy.IncludeDisabled);
			base.target.RegisterCallback<PointerCancelEvent>(OnPointerCancel, InvokePolicy.IncludeDisabled);
			base.target.RegisterCallback<PointerCaptureOutEvent>(OnPointerCaptureOut, InvokePolicy.IncludeDisabled);
		}

		protected override void UnregisterCallbacksFromTarget()
		{
			base.target.UnregisterCallback<PointerDownEvent>(OnPointerDown);
			base.target.UnregisterCallback<PointerMoveEvent>(OnPointerMove);
			base.target.UnregisterCallback<PointerUpEvent>(OnPointerUp);
			base.target.UnregisterCallback<PointerCancelEvent>(OnPointerCancel);
			base.target.UnregisterCallback<PointerCaptureOutEvent>(OnPointerCaptureOut);
			ResetActivePseudoState();
		}

		[Obsolete("OnMouseDown has been removed and replaced by its pointer-based equivalent. Please use OnPointerDown.", false)]
		protected void OnMouseDown(MouseDownEvent evt)
		{
			if (!active && CanStartManipulation(evt))
			{
				ProcessDownEvent(evt, evt.localMousePosition, PointerId.mousePointerId);
			}
		}

		[Obsolete("OnMouseMove has been removed and replaced by its pointer-based equivalent. Please use OnPointerMove.", false)]
		protected void OnMouseMove(MouseMoveEvent evt)
		{
			if (active)
			{
				ProcessMoveEvent(evt, evt.localMousePosition);
			}
		}

		[Obsolete("OnMouseUp has been removed and replaced by its pointer-based equivalent. Please use OnPointerUp.", false)]
		protected void OnMouseUp(MouseUpEvent evt)
		{
			if (active && CanStopManipulation(evt))
			{
				ProcessUpEvent(evt, evt.localMousePosition, PointerId.mousePointerId);
			}
		}

		protected void OnPointerDown(PointerDownEvent evt)
		{
			if (!active && CanStartManipulation(evt))
			{
				ProcessDownEvent(evt, evt.localPosition, evt.pointerId);
			}
		}

		protected void OnPointerMove(PointerMoveEvent evt)
		{
			if (active)
			{
				ProcessMoveEvent(evt, evt.localPosition);
			}
		}

		protected void OnPointerUp(PointerUpEvent evt)
		{
			if (active && CanStopManipulation(evt))
			{
				ProcessUpEvent(evt, evt.localPosition, evt.pointerId);
			}
		}

		private void OnPointerCancel(PointerCancelEvent evt)
		{
			if (active && CanStopManipulation(evt))
			{
				ProcessCancelEvent(evt, evt.pointerId);
			}
		}

		private void OnPointerCaptureOut(PointerCaptureOutEvent evt)
		{
			if (active)
			{
				ProcessCancelEvent(evt, evt.pointerId);
			}
		}

		private bool ContainsPointer(int pointerId)
		{
			VisualElement topElementUnderPointer = base.target.elementPanel.GetTopElementUnderPointer(pointerId);
			return base.target == topElementUnderPointer || base.target.Contains(topElementUnderPointer);
		}

		protected void Invoke(EventBase evt)
		{
			this.clicked?.Invoke();
			this.clickedWithEventInfo?.Invoke(evt);
		}

		internal void SimulateSingleClick(EventBase evt, int delayMs = 100)
		{
			base.target.pseudoStates |= PseudoStates.Active;
			m_PendingActivePseudoStateReset = base.target.schedule.Execute(ResetActivePseudoState);
			m_PendingActivePseudoStateReset.ExecuteLater(delayMs);
			Invoke(evt);
		}

		private void ResetActivePseudoState()
		{
			if (m_PendingActivePseudoStateReset != null)
			{
				base.target.pseudoStates &= ~PseudoStates.Active;
				m_PendingActivePseudoStateReset = null;
			}
		}

		protected virtual void ProcessDownEvent(EventBase evt, Vector2 localPosition, int pointerId)
		{
			active = true;
			m_ActivePointerId = pointerId;
			base.target.CapturePointer(pointerId);
			if (!(evt is IPointerEvent))
			{
				base.target.panel.ProcessPointerCapture(pointerId);
			}
			lastMousePosition = localPosition;
			if (IsRepeatable())
			{
				if (ContainsPointer(pointerId) && (base.target.enabledInHierarchy || acceptClicksIfDisabled))
				{
					Invoke(evt);
				}
				if (m_Repeater == null)
				{
					m_Repeater = base.target.schedule.Execute(OnTimer).Every(m_Interval).StartingIn(m_Delay);
				}
				else
				{
					m_Repeater.ExecuteLater(m_Delay);
				}
			}
			base.target.pseudoStates |= PseudoStates.Active;
			evt.StopImmediatePropagation();
		}

		protected virtual void ProcessMoveEvent(EventBase evt, Vector2 localPosition)
		{
			lastMousePosition = localPosition;
			if (ContainsPointer(m_ActivePointerId))
			{
				base.target.pseudoStates |= PseudoStates.Active;
			}
			else
			{
				base.target.pseudoStates &= ~PseudoStates.Active;
			}
			evt.StopPropagation();
		}

		protected virtual void ProcessUpEvent(EventBase evt, Vector2 localPosition, int pointerId)
		{
			active = false;
			m_ActivePointerId = -1;
			base.target.ReleasePointer(pointerId);
			if (!(evt is IPointerEvent))
			{
				base.target.panel.ProcessPointerCapture(pointerId);
			}
			base.target.pseudoStates &= ~PseudoStates.Active;
			if (IsRepeatable())
			{
				m_Repeater?.Pause();
			}
			else if (ContainsPointer(pointerId) && (base.target.enabledInHierarchy || acceptClicksIfDisabled))
			{
				Invoke(evt);
			}
			evt.StopPropagation();
		}

		protected virtual void ProcessCancelEvent(EventBase evt, int pointerId)
		{
			active = false;
			m_ActivePointerId = -1;
			base.target.ReleasePointer(pointerId);
			if (!(evt is IPointerEvent))
			{
				base.target.panel.ProcessPointerCapture(pointerId);
			}
			base.target.pseudoStates &= ~PseudoStates.Active;
			if (IsRepeatable())
			{
				m_Repeater?.Pause();
			}
			evt.StopPropagation();
		}
	}
	internal class ClickDetector
	{
		private class ButtonClickStatus
		{
			public VisualElement m_Target;

			public Vector3 m_PointerDownPosition;

			public long m_LastPointerDownTime;

			public int m_ClickCount;

			public void Reset()
			{
				m_Target = null;
				m_ClickCount = 0;
				m_LastPointerDownTime = 0L;
				m_PointerDownPosition = Vector3.zero;
			}
		}

		private List<ButtonClickStatus> m_ClickStatus;

		internal static int s_DoubleClickTime { get; set; } = -1;

		public ClickDetector()
		{
			m_ClickStatus = new List<ButtonClickStatus>(PointerId.maxPointers);
			for (int i = 0; i < PointerId.maxPointers; i++)
			{
				m_ClickStatus.Add(new ButtonClickStatus());
			}
			if (s_DoubleClickTime == -1)
			{
				s_DoubleClickTime = Event.GetDoubleClickTime();
			}
		}

		private void StartClickTracking(EventBase evt)
		{
			if (evt is IPointerEvent pointerEvent)
			{
				ButtonClickStatus buttonClickStatus = m_ClickStatus[pointerEvent.pointerId];
				VisualElement elementTarget = evt.elementTarget;
				if (elementTarget != buttonClickStatus.m_Target)
				{
					buttonClickStatus.Reset();
				}
				buttonClickStatus.m_Target = elementTarget;
				if (evt.timestamp - buttonClickStatus.m_LastPointerDownTime > s_DoubleClickTime)
				{
					buttonClickStatus.m_ClickCount = 1;
				}
				else
				{
					buttonClickStatus.m_ClickCount++;
				}
				buttonClickStatus.m_LastPointerDownTime = evt.timestamp;
				buttonClickStatus.m_PointerDownPosition = pointerEvent.position;
			}
		}

		private void SendClickEvent(EventBase evt)
		{
			if (!(evt is IPointerEvent pointerEvent))
			{
				return;
			}
			ButtonClickStatus buttonClickStatus = m_ClickStatus[pointerEvent.pointerId];
			VisualElement elementTarget = evt.elementTarget;
			if (elementTarget == null || !ContainsPointer(elementTarget, pointerEvent) || buttonClickStatus.m_Target == null || buttonClickStatus.m_ClickCount <= 0)
			{
				return;
			}
			VisualElement visualElement = buttonClickStatus.m_Target.FindCommonAncestor(evt.elementTarget);
			if (visualElement == null)
			{
				return;
			}
			using ClickEvent clickEvent = ClickEvent.GetPooled(pointerEvent, buttonClickStatus.m_ClickCount);
			clickEvent.elementTarget = visualElement;
			visualElement.SendEvent(clickEvent, DispatchMode.Immediate);
		}

		private void CancelClickTracking(EventBase evt)
		{
			if (evt is IPointerEvent pointerEvent)
			{
				ButtonClickStatus buttonClickStatus = m_ClickStatus[pointerEvent.pointerId];
				buttonClickStatus.Reset();
			}
		}

		public void ProcessEvent<TEvent>(PointerEventBase<TEvent> evt) where TEvent : PointerEventBase<TEvent>, new()
		{
			if (evt.eventTypeId == EventBase<PointerDownEvent>.TypeId() && evt.button == 0)
			{
				StartClickTracking(evt);
			}
			else if (evt.eventTypeId == EventBase<PointerMoveEvent>.TypeId())
			{
				if (evt.button == 0 && (evt.pressedButtons & 1) == 1)
				{
					StartClickTracking(evt);
					return;
				}
				if (evt.button == 0 && (evt.pressedButtons & 1) == 0)
				{
					SendClickEvent(evt);
					return;
				}
				ButtonClickStatus buttonClickStatus = m_ClickStatus[evt.pointerId];
				if (buttonClickStatus.m_Target != null)
				{
					buttonClickStatus.m_LastPointerDownTime = 0L;
				}
			}
			else if (evt.eventTypeId == EventBase<PointerCancelEvent>.TypeId())
			{
				CancelClickTracking(evt);
			}
			else if (evt.eventTypeId == EventBase<PointerUpEvent>.TypeId() && evt.button == 0)
			{
				SendClickEvent(evt);
			}
		}

		private static bool ContainsPointer(VisualElement element, IPointerEvent pe)
		{
			if (!element.worldBound.Contains(pe.position) || element.panel == null)
			{
				return false;
			}
			if (element.elementPanel.isFlat)
			{
				VisualElement topElementUnderPointer = element.elementPanel.GetTopElementUnderPointer(pe.pointerId);
				return element == topElementUnderPointer || element.Contains(topElementUnderPointer);
			}
			return true;
		}

		internal void Cleanup(List<VisualElement> elements)
		{
			foreach (ButtonClickStatus item in m_ClickStatus)
			{
				if (item.m_Target != null && elements.Contains(item.m_Target))
				{
					item.Reset();
				}
			}
		}
	}
