		[CreateProperty(ReadOnly = true)]
		public IEnumerable<object> selectedItems
		{
			get
			{
				foreach (int index in m_Selection.indices)
				{
					if (m_Selection.items.TryGetValue(index, out var item))
					{
						yield return item;
					}
					else
					{
						yield return null;
					}
					item = null;
				}
			}
		}

