				}
				if (!evt.ShouldSendNavigationMoveEvent())
				{
					return;
				}
			}
			if (!textElement.edition.multiline && (evt.keyCode == KeyCode.KeypadEnter || evt.keyCode == KeyCode.Return))
			{
				m_ShouldInvokeUpdateValue = true;
			}
			evt.StopPropagation();
			bool num;
			if (!textElement.edition.multiline)
			{
				if (c == '\n' || c == '\r' || c == '\n')
				{
					num = !evt.altKey;
					goto IL_0266;
				}
			}
			else if (c == '\n')
			{
				num = evt.shiftKey;
				goto IL_0266;
			}
			goto IL_0295;
			IL_0266:
			if (num)
			{
				ApplyTextIfNeeded();
