		protected override int CompareId(int id1, int id2)
		{
			if (id1 == id2)
			{
				return id1.CompareTo(id2);
			}
			int num = id1;
			int num2 = id2;
			List<int> value;
			using (CollectionPool<List<int>, int>.Get(out value))
			{
				while (num != BaseTreeView.invalidId)
