								return -1;
							}
							int id3 = ((i > 0) ? value[i - 1] : id1);
							int id4 = ((num3 > 0) ? value2[num3 - 1] : id2);
							int childIndexForId = m_TreeView.viewController.GetChildIndexForId(id3);
							int childIndexForId2 = m_TreeView.viewController.GetChildIndexForId(id4);
