					m_CurrentEvent = evt;
					m_DispatchStackFrame = ((m_GateDepth > 490) ? new StackTrace().FrameCount : 0);
					evt.Dispatch(panel);
				}
				finally
				{
					m_CurrentEvent = null;
				}
				evt.PostDispatch(panel);
