	internal class EventCallbackListPool
	{
		private readonly Stack<EventCallbackList> m_Stack = new Stack<EventCallbackList>();

		public EventCallbackList Get(EventCallbackList initializer)
		{
			EventCallbackList eventCallbackList;
			if (m_Stack.Count == 0)
			{
				eventCallbackList = ((initializer == null) ? new EventCallbackList() : new EventCallbackList(initializer));
			}
			else
			{
				eventCallbackList = m_Stack.Pop();
				if (initializer != null)
				{
					eventCallbackList.AddRange(initializer);
				}
			}
			return eventCallbackList;
		}

		public void Release(EventCallbackList element)
		{
			element.Clear();
			m_Stack.Push(element);
		}
	}
	internal class EventCallbackList
	{
		public static readonly EventCallbackList EmptyList = new EventCallbackList();

		private static readonly EventCallbackFunctorBase[] EmptyArray = new EventCallbackFunctorBase[0];

		private EventCallbackFunctorBase[] m_Array;

		private int m_Count;

		public int Count => m_Count;

		public Span<EventCallbackFunctorBase> Span => new Span<EventCallbackFunctorBase>(m_Array, 0, m_Count);

		public EventCallbackFunctorBase this[int i]
		{
			get
			{
				return m_Array[i];
			}
			set
			{
				m_Array[i] = value;
			}
		}

		public EventCallbackList()
		{
			m_Array = EmptyArray;
		}

		public EventCallbackList(EventCallbackList source)
		{
			m_Count = source.m_Count;
			m_Array = new EventCallbackFunctorBase[m_Count];
			Array.Copy(source.m_Array, m_Array, m_Count);
		}

		public bool Contains(long eventTypeId, [JetBrains.Annotations.NotNull] Delegate callback)
		{
			return Find(eventTypeId, callback) != null;
		}

		public EventCallbackFunctorBase Find(long eventTypeId, [JetBrains.Annotations.NotNull] Delegate callback)
		{
			for (int i = 0; i < m_Count; i++)
			{
				if (m_Array[i].IsEquivalentTo(eventTypeId, callback))
				{
					return m_Array[i];
				}
			}
			return null;
		}

		public bool Remove(long eventTypeId, [JetBrains.Annotations.NotNull] Delegate callback, out EventCallbackFunctorBase removedFunctor)
		{
			for (int i = 0; i < m_Count; i++)
			{
				if (m_Array[i].IsEquivalentTo(eventTypeId, callback))
				{
					removedFunctor = m_Array[i];
					m_Count--;
					Array.Copy(m_Array, i + 1, m_Array, i, m_Count - i);
					m_Array[m_Count] = null;
					return true;
				}
			}
			removedFunctor = null;
			return false;
		}

		public void Add(EventCallbackFunctorBase item)
		{
			if (m_Count >= m_Array.Length)
			{
				Array.Resize(ref m_Array, Mathf.NextPowerOfTwo(m_Count + 4));
			}
			m_Array[m_Count++] = item;
		}

		public void AddRange(EventCallbackList list)
		{
			if (m_Count + list.m_Count > m_Array.Length)
			{
				Array.Resize(ref m_Array, Mathf.NextPowerOfTwo(m_Count + list.m_Count));
			}
			Array.Copy(list.m_Array, 0, m_Array, m_Count, list.m_Count);
			m_Count += list.m_Count;
		}

		public void Clear()
		{
			Array.Clear(m_Array, 0, m_Count);
			m_Count = 0;
		}
	}
	internal class EventCallbackRegistry
	{
		internal struct DynamicCallbackList
		{
			private TrickleDown m_UseTrickleDown;

			[JetBrains.Annotations.NotNull]
			private EventCallbackList m_Callbacks;

			[CanBeNull]
			private EventCallbackList m_TemporaryCallbacks;

			[CanBeNull]
			private List<EventCallbackFunctorBase> m_UnregisteredCallbacksDuringInvoke;

			private int m_IsInvoking;

			public int Count => m_Callbacks.Count;

			public static DynamicCallbackList Create(TrickleDown useTrickleDown)
			{
				return new DynamicCallbackList
				{
					m_UseTrickleDown = useTrickleDown,
					m_Callbacks = EventCallbackList.EmptyList,
					m_TemporaryCallbacks = null,
					m_UnregisteredCallbacksDuringInvoke = null,
					m_IsInvoking = 0
				};
			}

			[JetBrains.Annotations.NotNull]
			public EventCallbackList GetCallbackListForWriting()
			{
				return (m_IsInvoking != 0) ? (m_TemporaryCallbacks ?? (m_TemporaryCallbacks = GetCallbackList(m_Callbacks))) : ((m_Callbacks != EventCallbackList.EmptyList) ? m_Callbacks : (m_Callbacks = GetCallbackList()));
			}

			[JetBrains.Annotations.NotNull]
			public readonly EventCallbackList GetCallbackListForReading()
			{
				return m_TemporaryCallbacks ?? m_Callbacks;
			}

			public bool UnregisterCallback(long eventTypeId, [JetBrains.Annotations.NotNull] Delegate callback)
			{
				EventCallbackList callbackListForWriting = GetCallbackListForWriting();
				if (!callbackListForWriting.Remove(eventTypeId, callback, out var removedFunctor))
				{
					return false;
				}
				if (m_IsInvoking > 0)
				{
					(m_UnregisteredCallbacksDuringInvoke ?? (m_UnregisteredCallbacksDuringInvoke = CollectionPool<List<EventCallbackFunctorBase>, EventCallbackFunctorBase>.Get())).Add(removedFunctor);
				}
				else
				{
					removedFunctor.Dispose();
				}
				return true;
			}

			public void Invoke(EventBase evt, BaseVisualElementPanel panel, VisualElement target)
			{
				BeginInvoke();
				try
				{
					bool flag = !evt.skipDisabledElements || target.enabledInHierarchy;
					long eventTypeId = evt.eventTypeId;
					Span<EventCallbackFunctorBase> span = m_Callbacks.Span;
					for (int i = 0; i < span.Length; i++)
					{
						EventCallbackFunctorBase eventCallbackFunctorBase = span[i];
						if (eventCallbackFunctorBase.eventTypeId == eventTypeId && target.elementPanel == panel && (flag || (eventCallbackFunctorBase.invokePolicy & InvokePolicy.IncludeDisabled) != InvokePolicy.Default))
						{
							if ((eventCallbackFunctorBase.invokePolicy & InvokePolicy.Once) != InvokePolicy.Default)
							{
								eventCallbackFunctorBase.UnregisterCallback(target, m_UseTrickleDown);
							}
							eventCallbackFunctorBase.Invoke(evt);
							if (evt.isImmediatePropagationStopped)
							{
								break;
							}
						}
					}
				}
				finally
				{
					EndInvoke();
				}
			}

			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			private void BeginInvoke()
			{
				m_IsInvoking++;
			}

			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			private void EndInvoke()
			{
				m_IsInvoking--;
				if (m_IsInvoking != 0 || m_TemporaryCallbacks == null)
				{
					return;
				}
				if (m_Callbacks != EventCallbackList.EmptyList)
				{
					ReleaseCallbackList(m_Callbacks);
				}
				m_Callbacks = GetCallbackList(m_TemporaryCallbacks);
				ReleaseCallbackList(m_TemporaryCallbacks);
				m_TemporaryCallbacks = null;
				if (m_UnregisteredCallbacksDuringInvoke == null)
				{
					return;
				}
				foreach (EventCallbackFunctorBase item in m_UnregisteredCallbacksDuringInvoke)
				{
					item.Dispose();
				}
				CollectionPool<List<EventCallbackFunctorBase>, EventCallbackFunctorBase>.Release(m_UnregisteredCallbacksDuringInvoke);
				m_UnregisteredCallbacksDuringInvoke = null;
			}
		}

		private static readonly EventCallbackListPool s_ListPool = new EventCallbackListPool();

		internal DynamicCallbackList m_TrickleDownCallbacks = DynamicCallbackList.Create(TrickleDown.TrickleDown);

		internal DynamicCallbackList m_BubbleUpCallbacks = DynamicCallbackList.Create(TrickleDown.NoTrickleDown);

		private static EventCallbackList GetCallbackList(EventCallbackList initializer = null)
		{
			return s_ListPool.Get(initializer);
		}

		private static void ReleaseCallbackList(EventCallbackList toRelease)
		{
			s_ListPool.Release(toRelease);
		}

		private ref DynamicCallbackList GetDynamicCallbackList(TrickleDown useTrickleDown)
		{
			return ref useTrickleDown == TrickleDown.TrickleDown ? ref m_TrickleDownCallbacks : ref m_BubbleUpCallbacks;
		}

		public void RegisterCallback<TEventType>([JetBrains.Annotations.NotNull] EventCallback<TEventType> callback, TrickleDown useTrickleDown = TrickleDown.NoTrickleDown, InvokePolicy invokePolicy = InvokePolicy.Default) where TEventType : EventBase<TEventType>, new()
		{
			long eventTypeId = EventBase<TEventType>.TypeId();
			ref DynamicCallbackList dynamicCallbackList = ref GetDynamicCallbackList(useTrickleDown);
			EventCallbackList callbackListForReading = dynamicCallbackList.GetCallbackListForReading();
			if (callbackListForReading.Find(eventTypeId, callback) is EventCallbackFunctor<TEventType> eventCallbackFunctor)
			{
				eventCallbackFunctor.invokePolicy = invokePolicy;
				return;
			}
			callbackListForReading = dynamicCallbackList.GetCallbackListForWriting();
			callbackListForReading.Add(EventCallbackFunctor<TEventType>.GetPooled(eventTypeId, callback, invokePolicy));
		}

		public void RegisterCallback<TEventType, TCallbackArgs>([JetBrains.Annotations.NotNull] EventCallback<TEventType, TCallbackArgs> callback, TCallbackArgs userArgs, TrickleDown useTrickleDown = TrickleDown.NoTrickleDown, InvokePolicy invokePolicy = InvokePolicy.Default) where TEventType : EventBase<TEventType>, new()
		{
			long eventTypeId = EventBase<TEventType>.TypeId();
			ref DynamicCallbackList dynamicCallbackList = ref GetDynamicCallbackList(useTrickleDown);
			EventCallbackList callbackListForReading = dynamicCallbackList.GetCallbackListForReading();
			if (callbackListForReading.Find(eventTypeId, callback) is EventCallbackFunctor<TEventType, TCallbackArgs> eventCallbackFunctor)
			{
				eventCallbackFunctor.invokePolicy = invokePolicy;
				eventCallbackFunctor.userArgs = userArgs;
			}
			else
			{
				callbackListForReading = dynamicCallbackList.GetCallbackListForWriting();
				callbackListForReading.Add(EventCallbackFunctor<TEventType, TCallbackArgs>.GetPooled(eventTypeId, callback, userArgs, invokePolicy));
			}
		}

		public bool UnregisterCallback<TEventType>([JetBrains.Annotations.NotNull] EventCallback<TEventType> callback, TrickleDown useTrickleDown = TrickleDown.NoTrickleDown) where TEventType : EventBase<TEventType>, new()
		{
			return GetDynamicCallbackList(useTrickleDown).UnregisterCallback(EventBase<TEventType>.TypeId(), callback);
		}

		public bool UnregisterCallback<TEventType, TCallbackArgs>([JetBrains.Annotations.NotNull] EventCallback<TEventType, TCallbackArgs> callback, TrickleDown useTrickleDown = TrickleDown.NoTrickleDown) where TEventType : EventBase<TEventType>, new()
		{
			return GetDynamicCallbackList(useTrickleDown).UnregisterCallback(EventBase<TEventType>.TypeId(), callback);
		}

		internal void InvokeCallbacks(EventBase evt, PropagationPhase propagationPhase)
		{
			VisualElement visualElement = (VisualElement)evt.currentTarget;
			BaseVisualElementPanel elementPanel = visualElement.elementPanel;
			switch (propagationPhase)
			{
			case PropagationPhase.TrickleDown:
				GetDynamicCallbackList(TrickleDown.TrickleDown).Invoke(evt, elementPanel, visualElement);
				break;
			case PropagationPhase.BubbleUp:
				GetDynamicCallbackList(TrickleDown.NoTrickleDown).Invoke(evt, elementPanel, visualElement);
				break;
			default:
				throw new ArgumentOutOfRangeException("propagationPhase", "Propagation phases other than TrickleDown and BubbleUp are not supported");
			}
		}

		public bool HasTrickleDownHandlers()
		{
			return m_TrickleDownCallbacks.Count > 0;
		}

		public bool HasBubbleHandlers()
		{
			return m_BubbleUpCallbacks.Count > 0;
		}
	}
	public enum PropagationPhase
	{
		None = 0,
		TrickleDown = 1,
		BubbleUp = 3,
		[Obsolete("PropagationPhase.AtTarget has been removed as part of an event propagation simplification. Events now propagate through the TrickleDown phase followed immediately by the BubbleUp phase. Please use TrickleDown or BubbleUp. You can check if the event target is the current element by testing event.target == this in your local callback.", false)]
		AtTarget = 2,
		[Obsolete("PropagationPhase.DefaultAction has been removed as part of an event propagation simplification. ExecuteDefaultAction now occurs as part of the BubbleUp phase. Please use BubbleUp.", false)]
		DefaultAction = 4,
		[Obsolete("PropagationPhase.DefaultActionAtTarget has been removed as part of an event propagation simplification. ExecuteDefaultActionAtTarget now occurs as part of the BubbleUp phase. Please use BubbleUp", false)]
		DefaultActionAtTarget = 5
	}
	internal static class EventDispatchUtilities
	{
		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private static void PropagateEvent(EventBase evt, [JetBrains.Annotations.NotNull] BaseVisualElementPanel panel, [JetBrains.Annotations.NotNull] VisualElement target, bool isCapturingTarget)
		{
			if ((evt as IPointerEventInternal)?.compatibilityMouseEvent is EventBase compatibilityEvt)
			{
				HandleEventAcrossPropagationPathWithCompatibilityEvent(evt, compatibilityEvt, panel, target, isCapturingTarget);
			}
			else
			{
				HandleEventAcrossPropagationPath(evt, panel, target, isCapturingTarget);
			}
		}

		public static void HandleEventAtTargetAndDefaultPhase(EventBase evt, [JetBrains.Annotations.NotNull] BaseVisualElementPanel panel, [JetBrains.Annotations.NotNull] VisualElement target)
		{
			int eventCategories = evt.eventCategories;
			if (!target.HasSelfEventInterests(eventCategories) || evt.isPropagationStopped)
			{
				return;
			}
			evt.currentTarget = target;
			try
			{
				Debug.Assert(!(evt is IPointerEventInternal pointerEventInternal) || pointerEventInternal.compatibilityMouseEvent == null, "!(evt is IPointerEventInternal pe) || pe.compatibilityMouseEvent == null");
				evt.propagationPhase = PropagationPhase.TrickleDown;
				if (target.HasTrickleDownEventCallbacks(eventCategories))
				{
					HandleEvent_TrickleDownCallbacks(evt, panel, target);
					if (evt.isImmediatePropagationStopped)
					{
						return;
					}
				}
				if (target.HasTrickleDownHandleEvent(eventCategories))
				{
					HandleEvent_TrickleDownHandleEvent(evt, panel, target, Disabled(evt, target));
				}
				if (evt.isPropagationStopped)
				{
					return;
				}
				evt.propagationPhase = PropagationPhase.BubbleUp;
				if (target.HasBubbleUpHandleEvent(eventCategories))
				{
					bool disabled = Disabled(evt, target);
					HandleEvent_DefaultActionAtTarget(evt, panel, target, disabled);
					HandleEvent_BubbleUpHandleEvent(evt, panel, target, disabled);
					HandleEvent_DefaultAction(evt, panel, target, disabled);
					if (evt.isImmediatePropagationStopped)
					{
						return;
					}
				}
				if (target.HasBubbleUpEventCallbacks(eventCategories))
				{
					HandleEvent_BubbleUpCallbacks(evt, panel, target);
				}
			}
			finally
			{
				evt.currentTarget = null;
				evt.propagationPhase = PropagationPhase.None;
			}
		}

		private static void HandleEventAcrossPropagationPath(EventBase evt, [JetBrains.Annotations.NotNull] BaseVisualElementPanel panel, [JetBrains.Annotations.NotNull] VisualElement target, bool isCapturingTarget)
		{
			int eventCategories = evt.eventCategories;
			if (!target.HasParentEventInterests(eventCategories) || evt.isPropagationStopped)
			{
				return;
			}
			using PropagationPaths propagationPaths = PropagationPaths.Build(target, evt, eventCategories);
			try
			{
				Debug.Assert(!evt.dispatch, "Event is being dispatched recursively.");
				evt.dispatch = true;
				evt.propagationPhase = PropagationPhase.TrickleDown;
				int num = propagationPaths.trickleDownPath.Count - 1;
				if (isCapturingTarget && num >= 0)
				{
					num = ((propagationPaths.trickleDownPath[0] != target) ? (-1) : 0);
				}
				while (num >= 0)
				{
					VisualElement visualElement = (VisualElement)(evt.currentTarget = propagationPaths.trickleDownPath[num]);
					if (visualElement.HasTrickleDownEventCallbacks(eventCategories))
					{
						HandleEvent_TrickleDownCallbacks(evt, panel, visualElement);
						if (evt.isImmediatePropagationStopped)
						{
							return;
						}
					}
					if (visualElement.HasTrickleDownHandleEvent(eventCategories))
					{
						HandleEvent_TrickleDownHandleEvent(evt, panel, visualElement, Disabled(evt, visualElement));
					}
					if (evt.isPropagationStopped)
					{
						return;
					}
					num--;
				}
				evt.propagationPhase = PropagationPhase.BubbleUp;
				foreach (VisualElement item in propagationPaths.bubbleUpPath)
				{
					VisualElement visualElement2 = (VisualElement)(evt.currentTarget = item);
					if (visualElement2.HasBubbleUpHandleEvent(eventCategories))
					{
						HandleEvent_BubbleUpAllDefaultActions(evt, panel, visualElement2, Disabled(evt, visualElement2), isCapturingTarget);
						if (evt.isImmediatePropagationStopped)
						{
							break;
						}
					}
					if (visualElement2.HasBubbleUpEventCallbacks(eventCategories) && (!isCapturingTarget || visualElement2 == target))
					{
						HandleEvent_BubbleUpCallbacks(evt, panel, visualElement2);
					}
					if (evt.isPropagationStopped)
					{
						break;
					}
				}
			}
			finally
			{
				evt.currentTarget = null;
				evt.propagationPhase = PropagationPhase.None;
				evt.dispatch = false;
			}
		}

		private static void HandleEventAcrossPropagationPathWithCompatibilityEvent(EventBase evt, [JetBrains.Annotations.NotNull] EventBase compatibilityEvt, [JetBrains.Annotations.NotNull] BaseVisualElementPanel panel, [JetBrains.Annotations.NotNull] VisualElement target, bool isCapturingTarget)
		{
			int eventCategories = evt.eventCategories | compatibilityEvt.eventCategories;
			if (!target.HasParentEventInterests(eventCategories) || evt.isPropagationStopped || compatibilityEvt.isPropagationStopped)
			{
				return;
			}
			compatibilityEvt.elementTarget = target;
			compatibilityEvt.skipDisabledElements = evt.skipDisabledElements;
			using PropagationPaths propagationPaths = PropagationPaths.Build(target, evt, eventCategories);
			try
			{
				Debug.Assert(!evt.dispatch, "Event is being dispatched recursively.");
				evt.dispatch = true;
				evt.propagationPhase = PropagationPhase.TrickleDown;
				compatibilityEvt.propagationPhase = PropagationPhase.TrickleDown;
				int num = propagationPaths.trickleDownPath.Count - 1;
				if (isCapturingTarget && num >= 0)
				{
					num = ((propagationPaths.trickleDownPath[0] != target) ? (-1) : 0);
				}
				while (num >= 0)
				{
					VisualElement visualElement = (VisualElement)(compatibilityEvt.currentTarget = (evt.currentTarget = propagationPaths.trickleDownPath[num]));
					if (visualElement.HasTrickleDownEventCallbacks(eventCategories))
					{
						HandleEvent_TrickleDownCallbacks(evt, panel, visualElement);
						if (evt.isImmediatePropagationStopped)
						{
							return;
						}
						if (panel.ShouldSendCompatibilityMouseEvents((IPointerEvent)evt))
						{
							HandleEvent_TrickleDownCallbacks(compatibilityEvt, panel, visualElement);
							if (evt.isImmediatePropagationStopped)
