		internal static void SetElementWithSoftPointerCapture(int pointerId, VisualElement element, Camera camera)
		{
			RuntimePanel runtimePanel = element?.elementPanel as RuntimePanel;
			s_PlayerPanelWithSoftPointerCapture[pointerId] = runtimePanel;
			s_CameraWithSoftPointerCapture[pointerId] = camera;
			ref UIDocument reference = ref s_WorldSpaceDocumentWithSoftPointerCapture[pointerId];
			if (reference != null)
			{
				reference.softPointerCaptures &= ~(1 << pointerId);
			}
			reference = ((runtimePanel != null && runtimePanel.drawsInCameras) ? UIDocument.FindRootUIDocument(element) : null);
			if (reference != null)
			{
				reference.softPointerCaptures |= 1 << pointerId;
			}
		}

		internal static TrackedPointerState GetTrackedState(int pointerId, bool createIfNull = false)
		{
			int num = pointerId - PointerId.trackedPointerIdBase;
			if (num < 0 || num >= PointerId.trackedPointerCount)
			{
				return null;
			}
			if (createIfNull)
			{
				RuntimePointerState[] array = s_RuntimePointerStates;
				if (array[pointerId] == null)
				{
					array[pointerId] = new TrackedPointerState();
				}
			}
			return (TrackedPointerState)s_RuntimePointerStates[pointerId];
		}

		internal static void RemoveTrackedState(int pointerId)
		{
			int num = pointerId - PointerId.trackedPointerIdBase;
			if (num >= 0 && num < PointerId.trackedPointerCount)
			{
				s_RuntimePointerStates[pointerId] = null;
			}
		}

		internal static ScreenPointerState GetScreenPointerState(int pointerId, bool createIfNull = false)
		{
			int num = pointerId - PointerId.trackedPointerIdBase;
			if (num >= 0 && num < PointerId.trackedPointerCount)
			{
				return null;
			}
			if (createIfNull)
			{
				RuntimePointerState[] array = s_RuntimePointerStates;
				if (array[pointerId] == null)
				{
					array[pointerId] = new ScreenPointerState();
				}
			}
			return (ScreenPointerState)s_RuntimePointerStates[pointerId];
		}
	}
	public static class PointerType
	{
		public static readonly string mouse = "mouse";

		public static readonly string touch = "touch";

		public static readonly string pen = "pen";

		public static readonly string tracked = "tracked";

		public static readonly string unknown = "";

		internal static string GetPointerType(int pointerId)
		{
			if (pointerId == PointerId.mousePointerId)
			{
				return mouse;
			}
			if (pointerId >= PointerId.trackedPointerIdBase)
			{
				return tracked;
			}
			if (pointerId >= PointerId.penPointerIdBase)
			{
				return pen;
			}
			if (pointerId >= PointerId.touchPointerIdBase)
			{
				return touch;
			}
			return unknown;
		}

		internal static bool IsDirectManipulationDevice(string pointerType)
		{
			return (object)pointerType == touch || (object)pointerType == pen;
		}
	}
	public static class PointerId
	{
		public static readonly int maxPointers = 32;

		public static readonly int invalidPointerId = -1;

		public static readonly int mousePointerId = 0;

		public static readonly int touchPointerIdBase = 1;

		public static readonly int touchPointerCount = 20;

		public static readonly int penPointerIdBase = touchPointerIdBase + touchPointerCount;

		public static readonly int penPointerCount = 2;

		public static readonly int trackedPointerIdBase = penPointerIdBase + penPointerCount;

		public static readonly int trackedPointerCount = 8;

		internal static readonly int[] screenHoveringPointers = new int[1] { mousePointerId };
	}
