			if (!m_DisableNoThemeWarning && themeUss == null)
			{
				Debug.LogWarning("No Theme Style Sheet set to PanelSettings " + base.name + ", UI will not render properly", this);
			}
			UpdateScreenDPI();
			InitializeShaders();
			AssignICUData();
