		private float pixelsPerUnit => containerPanel?.pixelsPerUnit ?? 1f;

		internal void ApplySortingOrder()
		{
			AddRootVisualElementToTree();
		}

		internal static UIDocument FindRootUIDocument(VisualElement element)
		{
			UIDocument uIDocument = element.GetFirstOfType<UIDocumentRootElement>()?.document;
			while (uIDocument?.parentUI != null)
			{
				uIDocument = uIDocument.parentUI;
			}
			return uIDocument;
		}

		private UIDocument()
		{
			m_UIDocumentCreationIndex = s_CurrentUIDocumentCounter++;
		}

		private void Awake()
		{
			SetupFromHierarchy();
		}

		private void OnEnable()
		{
			_Enable();
			EnabledDocumentCount++;
		}

		private void _Enable()
		{
			if (parentUI != null && m_PanelSettings == null)
			{
				m_PanelSettings = parentUI.m_PanelSettings;
			}
			if (m_RootVisualElement == null)
			{
				RecreateUI();
			}
			else
			{
				AddRootVisualElementToTree();
			}
			if (TryGetComponent<UIRenderer>(out var component))
			{
				component.enabled = true;
			}
		}

		private void LateUpdate()
		{
			DoUpdate();
		}

		internal void DoUpdate()
		{
			if (m_RootVisualElement == null || panelSettings == null || panelSettings.panel == null)
			{
				RemoveWorldSpaceCollider();
				return;
			}
			AddOrRemoveRendererComponent();
			if (isWorldSpace)
			{
				if (isTransformControlledByGameObject)
				{
					SetTransform();
				}
				else
				{
					ClearTransform();
				}
				UpdateRenderer();
				if (panelSettings.colliderUpdateMode != ColliderUpdateMode.Keep)
				{
					UpdateWorldSpaceCollider(panelSettings.colliderUpdateMode);
				}
			}
			else
			{
				RemoveWorldSpaceCollider();
				if (m_RootHasWorldTransform)
				{
					ClearTransform();
				}
			}
			UpdateIsWorldSpaceRootFlag();
		}

		private void UpdateRenderer()
		{
			if (!TryGetComponent<UIRenderer>(out var component))
			{
				m_RootVisualElement.uiRenderer = null;
				return;
			}
			m_RootVisualElement.uiRenderer = component;
			component.skipRendering = parentUI != null || pixelsPerUnit < Mathf.Epsilon;
			BaseRuntimePanel baseRuntimePanel = (BaseRuntimePanel)m_RootVisualElement.panel;
			if (baseRuntimePanel != null)
			{
				Bounds bounds = SanitizeRendererBounds(rootVisualElement.localBounds3D);
				Matrix4x4 matrix = TransformToGameObjectMatrix();
				VisualElement.TransformAlignedBounds(ref matrix, ref bounds);
				component.localBounds = bounds;
				UpdateIsWorldSpaceRootFlag();
			}
		}

		private Bounds SanitizeRendererBounds(Bounds b)
		{
			if (float.IsNaN(b.size.x) || float.IsNaN(b.size.y) || float.IsNaN(b.size.z))
			{
				b = new Bounds(Vector3.zero, Vector3.zero);
			}
			if (b.size.x < 0f || b.size.y < 0f)
			{
				b.size = Vector3.zero;
			}
			return b;
		}

		private void AddOrRemoveRendererComponent()
		{
			TryGetComponent<UIRenderer>(out var component);
			if (isWorldSpace)
			{
				if (component == null)
				{
					base.gameObject.AddComponent<UIRenderer>();
				}
			}
			else
			{
				UIRUtility.Destroy(component);
			}
		}

		internal void UpdateWorldSpaceCollider(ColliderUpdateMode mode)
		{
			if (parentUI != null)
			{
				return;
			}
			if (containerPanel == null)
			{
				RemoveWorldSpaceCollider();
				return;
			}
			Bounds b;
			if (mode == ColliderUpdateMode.MatchBoundingBox)
			{
				b = WorldSpaceInput.GetPicking3DWorldBounds(rootVisualElement);
			}
			else
			{
				Rect worldBound = rootVisualElement.worldBound;
				b = new Bounds(worldBound.center, worldBound.size);
			}
			if (!IsValidBounds(in b))
			{
				RemoveWorldSpaceCollider();
				return;
			}
			if (m_WorldSpaceCollider == null)
			{
				m_WorldSpaceCollider = base.gameObject.AddComponent<BoxCollider>();
				m_WorldSpaceCollider.isTrigger = panelSettings.colliderIsTrigger;
			}
			if (b.center != m_WorldSpaceCollider.center || b.size != m_WorldSpaceCollider.size)
			{
				m_WorldSpaceCollider.center = b.center;
				m_WorldSpaceCollider.size = b.size;
			}
		}

		internal void RemoveWorldSpaceCollider()
		{
			UIRUtility.Destroy(m_WorldSpaceCollider);
			m_WorldSpaceCollider = null;
		}

		private static bool IsValidBounds(in Bounds b)
		{
			Vector3 extents = b.extents;
			int num = ((extents.x > 0f) ? 1 : 0) + ((extents.y > 0f) ? 1 : 0) + ((extents.z > 0f) ? 1 : 0);
			return num >= 2;
		}

		private void UpdateIsWorldSpaceRootFlag()
		{
			bool flag = !panelSettings.panel.isFlat && parentUI == null;
			if (m_RootVisualElement.isWorldSpaceRootUIDocument != flag)
			{
				m_RootVisualElement.isWorldSpaceRootUIDocument = flag;
				m_RootVisualElement.MarkDirtyRepaint();
			}
		}

		private void SetTransform()
		{
			ComputeTransform(base.transform, out var matrix);
			m_RootVisualElement.style.transformOrigin = new TransformOrigin(Vector3.zero);
			m_RootVisualElement.style.translate = new Translate(matrix.GetPosition());
			m_RootVisualElement.style.rotate = new Rotate(matrix.rotation);
			m_RootVisualElement.style.scale = new Scale(matrix.lossyScale);
			m_RootHasWorldTransform = true;
		}

		private void ClearTransform()
		{
			m_RootVisualElement.style.transformOrigin = StyleKeyword.Null;
			m_RootVisualElement.style.translate = StyleKeyword.Null;
			m_RootVisualElement.style.rotate = StyleKeyword.Null;
			m_RootVisualElement.style.scale = StyleKeyword.Null;
			m_RootHasWorldTransform = false;
		}

		private Matrix4x4 ScaleAndFlipMatrix()
		{
			float num = pixelsPerUnit;
			if (num < Mathf.Epsilon)
			{
				return Matrix4x4.identity;
			}
			float num2 = 1f / num;
			Vector3 s = Vector3.one * num2;
			Quaternion q = Quaternion.AngleAxis(180f, Vector3.right);
			return Matrix4x4.TRS(Vector3.zero, q, s);
		}

		private Bounds LocalBoundsFromPivotSource()
		{
			Bounds localBounds3DWithoutNested3D = m_RootVisualElement.localBounds3DWithoutNested3D;
			Bounds b;
			if (m_PivotReferenceSize == PivotReferenceSize.BoundingBox)
			{
				b = localBounds3DWithoutNested3D;
			}
			else
			{
				Rect layout = m_RootVisualElement.layout;
				Vector2 center = layout.center;
				Vector2 size = layout.size;
				float z = localBounds3DWithoutNested3D.size.z;
				b = new Bounds(new Vector3(center.x, center.y, localBounds3DWithoutNested3D.min.z + z * 0.5f), new Vector3(size.x, size.y, z));
			}
			return SanitizeRendererBounds(b);
		}

		private Vector2 PivotOffset()
		{
			Vector2 pivotAsPercent = GetPivotAsPercent(m_Pivot);
			Bounds bounds = LocalBoundsFromPivotSource();
			return -(Vector2)bounds.min + new Vector2((0f - bounds.size.x) * pivotAsPercent.x, (0f - bounds.size.y) * pivotAsPercent.y);
		}

		private Matrix4x4 TransformToGameObjectMatrix()
		{
			Matrix4x4 m = ScaleAndFlipMatrix();
			MathUtils.PostApply2DOffset(ref m, PivotOffset());
			return m;
		}

		private void ComputeTransform(Transform transform, out Matrix4x4 matrix)
		{
			if (parentUI == null)
			{
				matrix = TransformToGameObjectMatrix();
				return;
			}
			Matrix4x4 matrix4x = parentUI.ScaleAndFlipMatrix();
			Matrix4x4 inverse = matrix4x.inverse;
			Matrix4x4 localToWorldMatrix = transform.localToWorldMatrix;
			Matrix4x4 worldToLocalMatrix = parentUI.transform.worldToLocalMatrix;
			matrix = inverse * worldToLocalMatrix * localToWorldMatrix * matrix4x;
			MathUtils.PreApply2DOffset(ref matrix, -parentUI.PivotOffset());
			MathUtils.PostApply2DOffset(ref matrix, PivotOffset());
		}

		private static Vector2 GetPivotAsPercent(Pivot origin)
		{
			return origin switch
			{
				Pivot.Center => new Vector2(0.5f, 0.5f), 
				Pivot.TopLeft => new Vector2(0f, 0f), 
				Pivot.TopCenter => new Vector2(0.5f, 0f), 
				Pivot.TopRight => new Vector2(1f, 0f), 
				Pivot.LeftCenter => new Vector2(0f, 0.5f), 
				Pivot.RightCenter => new Vector2(1f, 0.5f), 
				Pivot.BottomLeft => new Vector2(0f, 1f), 
				Pivot.BottomCenter => new Vector2(0.5f, 1f), 
				Pivot.BottomRight => new Vector2(1f, 1f), 
				_ => new Vector2(0.5f, 0.5f), 
			};
		}

		private void SetupFromHierarchy()
		{
			if (parentUI != null)
			{
				parentUI.RemoveChild(this);
			}
			parentUI = FindUIDocumentParent();
		}

		private UIDocument FindUIDocumentParent()
		{
			Transform transform = base.transform;
			Transform parent = transform.parent;
			if (parent != null)
			{
				UIDocument[] componentsInParent = parent.GetComponentsInParent<UIDocument>(includeInactive: true);
				if (componentsInParent != null && componentsInParent.Length != 0)
				{
					return componentsInParent[0];
				}
			}
			return null;
		}

		internal void Reset()
		{
			if (parentUI == null)
			{
				m_PreviousPanelSettings?.DetachUIDocument(this);
				panelSettings = null;
			}
			SetupFromHierarchy();
			if (parentUI != null)
			{
				m_PanelSettings = parentUI.m_PanelSettings;
				AddRootVisualElementToTree();
			}
			else if (m_PanelSettings != null)
			{
				AddRootVisualElementToTree();
			}
		}

		internal void AddChildAndInsertContentToVisualTree(UIDocument child)
		{
			if (m_ChildrenContent == null)
			{
				m_ChildrenContent = new UIDocumentList();
			}
			else
			{
				m_ChildrenContent.RemoveFromListAndFromVisualTree(child);
			}
			bool ignoreContentContainer = child.position == Position.Absolute;
			m_ChildrenContent.AddToListAndToVisualTree(child, m_RootVisualElement, ignoreContentContainer, m_FirstChildInsertIndex);
		}

		private void RemoveChild(UIDocument child)
		{
			m_ChildrenContent?.RemoveFromListAndFromVisualTree(child);
		}

		private void RecreateUI()
		{
			if (m_RootVisualElement != null)
			{
				RemoveFromHierarchy();
				rootVisualElement = null;
			}
			if (sourceAsset != null)
			{
				rootVisualElement = new UIDocumentRootElement(this, sourceAsset);
				try
				{
					sourceAsset.CloneTree(m_RootVisualElement);
				}
				catch (Exception exception)
				{
					Debug.LogError("The UXML file set for the UIDocument could not be cloned.");
					Debug.LogException(exception);
				}
			}
			if (m_RootVisualElement == null)
			{
				rootVisualElement = new UIDocumentRootElement(this, null)
				{
					name = base.gameObject.name + "-container"
				};
			}
			else
			{
				m_RootVisualElement.name = base.gameObject.name + "-container";
			}
			m_RootVisualElement.pickingMode = PickingMode.Ignore;
			if (base.isActiveAndEnabled)
			{
				AddRootVisualElementToTree();
			}
			m_FirstChildInsertIndex = m_RootVisualElement.childCount;
			if (m_ChildrenContent != null)
			{
				if (m_ChildrenContentCopy == null)
				{
					m_ChildrenContentCopy = new List<UIDocument>(m_ChildrenContent.m_AttachedUIDocuments);
				}
				else
				{
					m_ChildrenContentCopy.AddRange(m_ChildrenContent.m_AttachedUIDocuments);
				}
				foreach (UIDocument item in m_ChildrenContentCopy)
				{
					if (item.isActiveAndEnabled)
					{
						if (item.m_RootVisualElement == null)
						{
							item.RecreateUI();
						}
						else
						{
							AddChildAndInsertContentToVisualTree(item);
						}
					}
				}
				m_ChildrenContentCopy.Clear();
			}
			SetupRootClassList();
		}

		internal void SetupPosition()
		{
			if (m_RootVisualElement != null && !(m_ParentUI == null))
			{
				if (isTransformControlledByGameObject)
				{
					m_RootVisualElement.style.position = Position.Absolute;
				}
				else
				{
					m_RootVisualElement.style.position = m_Position;
				}
				m_ParentUI.AddChildAndInsertContentToVisualTree(this);
			}
		}

		private void SetupRootClassList()
		{
			if (m_RootVisualElement != null)
			{
				if (!isWorldSpace)
				{
					m_RootVisualElement.EnableInClassList("unity-ui-document__root", parentUI == null);
					m_RootVisualElement.style.position = StyleKeyword.Null;
					m_RootVisualElement.style.width = StyleKeyword.Null;
					m_RootVisualElement.style.height = StyleKeyword.Null;
				}
				else
				{
					SetupWorldSpaceSize();
				}
				SetupPosition();
			}
		}

		private void SetupWorldSpaceSize()
		{
			if (m_RootVisualElement != null)
			{
				if (!isTransformControlledByGameObject)
				{
					m_RootVisualElement.style.width = StyleKeyword.Null;
					m_RootVisualElement.style.height = StyleKeyword.Null;
				}
				else if (m_WorldSpaceSizeMode == WorldSpaceSizeMode.Fixed)
				{
					m_RootVisualElement.style.position = Position.Absolute;
					m_RootVisualElement.style.width = m_WorldSpaceWidth;
					m_RootVisualElement.style.height = m_WorldSpaceHeight;
				}
				else
				{
					m_RootVisualElement.style.position = Position.Absolute;
					m_RootVisualElement.style.width = StyleKeyword.Null;
					m_RootVisualElement.style.height = StyleKeyword.Null;
				}
			}
		}

		private void AddRootVisualElementToTree()
		{
			if (base.enabled)
			{
				if (parentUI != null)
				{
					parentUI.AddChildAndInsertContentToVisualTree(this);
				}
				else if (m_PanelSettings != null)
				{
					m_PanelSettings.AttachAndInsertUIDocumentToVisualTree(this);
				}
			}
		}

		private void RemoveFromHierarchy()
		{
			if (parentUI != null)
			{
				parentUI.RemoveChild(this);
			}
			else if (m_PanelSettings != null)
			{
				m_PanelSettings.DetachUIDocument(this);
			}
		}

		private void OnDisable()
		{
			EnabledDocumentCount--;
			PointerDeviceState.RemoveDocumentData(this);
			RemoveWorldSpaceCollider();
			if (m_RootVisualElement != null)
			{
				RemoveFromHierarchy();
				rootVisualElement = null;
			}
			if (TryGetComponent<UIRenderer>(out var component))
			{
				component.enabled = false;
			}
		}

		private void OnTransformChildrenChanged()
		{
			if (m_ChildrenContent == null)
			{
				return;
			}
			if (m_ChildrenContentCopy == null)
			{
				m_ChildrenContentCopy = new List<UIDocument>(m_ChildrenContent.m_AttachedUIDocuments);
			}
			else
			{
				m_ChildrenContentCopy.AddRange(m_ChildrenContent.m_AttachedUIDocuments);
			}
			foreach (UIDocument item in m_ChildrenContentCopy)
			{
				item.ReactToHierarchyChanged();
			}
			m_ChildrenContentCopy.Clear();
		}

		private void OnTransformParentChanged()
		{
			ReactToHierarchyChanged();
		}

		internal void ReactToHierarchyChanged()
		{
			SetupFromHierarchy();
			if (parentUI != null)
			{
				panelSettings = parentUI.m_PanelSettings;
			}
			m_RootVisualElement?.RemoveFromHierarchy();
			AddRootVisualElementToTree();
			SetupRootClassList();
		}
	}
	internal static class UIDocumentHierarchyUtil
	{
		internal static UIDocumentHierarchicalIndexComparer indexComparer = new UIDocumentHierarchicalIndexComparer();

		internal static int FindHierarchicalSortedIndex(SortedDictionary<UIDocumentHierarchicalIndex, UIDocument> children, UIDocument child)
		{
			int num = 0;
			foreach (UIDocument value in children.Values)
			{
				if (value == child)
				{
					return num;
				}
				if (value.rootVisualElement != null && value.rootVisualElement.parent != null)
				{
					num++;
				}
			}
			return num;
		}

		internal static void SetHierarchicalIndex(Transform childTransform, Transform directParentTransform, Transform mainParentTransform, out UIDocumentHierarchicalIndex hierarchicalIndex)
		{
			if (mainParentTransform == null || childTransform == null)
			{
				hierarchicalIndex.pathToParent = null;
				return;
			}
			if (directParentTransform == mainParentTransform)
			{
				hierarchicalIndex.pathToParent = new int[1] { childTransform.GetSiblingIndex() };
				return;
			}
			List<int> list = new List<int>();
			while (mainParentTransform != childTransform && childTransform != null)
			{
				list.Add(childTransform.GetSiblingIndex());
				childTransform = childTransform.parent;
			}
			list.Reverse();
			hierarchicalIndex.pathToParent = list.ToArray();
		}

		internal static void SetGlobalIndex(Transform objectTransform, Transform directParentTransform, out UIDocumentHierarchicalIndex globalIndex)
		{
			if (objectTransform == null)
			{
				globalIndex.pathToParent = null;
				return;
			}
			if (directParentTransform == null)
			{
				globalIndex.pathToParent = new int[1] { objectTransform.GetSiblingIndex() };
				return;
			}
			List<int> list = new List<int> { objectTransform.GetSiblingIndex() };
			while (directParentTransform != null)
			{
				list.Add(directParentTransform.GetSiblingIndex());
				directParentTransform = directParentTransform.parent;
			}
			list.Reverse();
			globalIndex.pathToParent = list.ToArray();
		}
	}
	internal class UIDocumentHierarchicalIndexComparer : IComparer<UIDocumentHierarchicalIndex>
	{
		public int Compare(UIDocumentHierarchicalIndex x, UIDocumentHierarchicalIndex y)
		{
			return x.CompareTo(y);
		}
	}
	internal struct UIDocumentHierarchicalIndex : IComparable<UIDocumentHierarchicalIndex>
	{
		internal int[] pathToParent;

		public int CompareTo(UIDocumentHierarchicalIndex other)
		{
			if (pathToParent == null)
			{
				if (other.pathToParent == null)
				{
					return 0;
				}
				return 1;
			}
			if (other.pathToParent == null)
			{
				return -1;
			}
			int num = pathToParent.Length;
			int num2 = other.pathToParent.Length;
			for (int i = 0; i < num && i < num2; i++)
			{
				if (pathToParent[i] < other.pathToParent[i])
				{
					return -1;
				}
				if (pathToParent[i] > other.pathToParent[i])
				{
					return 1;
				}
			}
			if (num > num2)
			{
				return 1;
			}
			if (num < num2)
			{
				return -1;
			}
			return 0;
		}

		public override string ToString()
		{
			StringBuilder stringBuilder = new StringBuilder("pathToParent = [");
			if (pathToParent != null)
			{
				int num = pathToParent.Length;
				for (int i = 0; i < num; i++)
				{
					stringBuilder.Append(pathToParent[i]);
					if (i < num - 1)
					{
						stringBuilder.Append(", ");
					}
				}
			}
			stringBuilder.Append("]");
			return stringBuilder.ToString();
		}
	}
	internal static class WorldSpaceInput
	{
		public struct PickResult
		{
			public static readonly PickResult Empty = new PickResult
			{
				distance = float.PositiveInfinity
			};

			public Collider collider;

			public UIDocument document;

			public VisualElement pickedElement;

			public float distance;

			public Vector3 normal;

			public Vector3 point;

			public Vector3 localPoint;

			internal void ComputeCollisionData(Ray ray)
			{
				point = ray.origin + ray.direction * distance;
				if (document != null && pickedElement != null)
				{
					localPoint = pickedElement.worldTransformInverse.MultiplyPoint3x4(document.transform.InverseTransformPoint(point));
					normal = document.transform.TransformDirection(pickedElement.worldTransformRef.MultiplyVector(Vector3.forward));
				}
			}
		}

		public static VisualElement Pick3D(UIDocument document, Ray worldRay)
		{
			Ray documentRay = document.transform.worldToLocalMatrix.TransformRay(worldRay);
			return Pick_Internal(document, documentRay);
		}

		public static void PickAll3D(UIDocument document, Ray worldRay, List<VisualElement> outResults)
		{
			Ray documentRay = document.transform.worldToLocalMatrix.TransformRay(worldRay);
			Pick_Internal(document, documentRay, outResults);
		}

		public static VisualElement Pick3D(UIDocument document, Ray worldRay, out float distance)
		{
			Ray ray = document.transform.worldToLocalMatrix.TransformRay(worldRay);
			VisualElement visualElement = Pick_Internal(document, ray);
			if (visualElement != null)
			{
				visualElement.IntersectWorldRay(ray, out var distance2, out var _);
				Vector3 position = ray.origin + ray.direction * distance2;
				Vector3 b = document.transform.TransformPoint(position);
				distance = Vector3.Distance(worldRay.origin, b);
			}
			else
			{
				distance = float.PositiveInfinity;
			}
			return visualElement;
		}

		public static bool Pick3D(UIDocument document, Ray worldRay, out PickResult pickResult)
		{
			Ray ray = document.transform.worldToLocalMatrix.TransformRay(worldRay);
			VisualElement visualElement = Pick_Internal(document, ray);
			if (visualElement == null)
			{
				pickResult = PickResult.Empty;
				return false;
			}
			visualElement.IntersectWorldRay(ray, out var distance, out var _);
			Vector3 position = ray.origin + ray.direction * distance;
			Vector3 b = document.transform.TransformPoint(position);
			float distance2 = Vector3.Distance(worldRay.origin, b);
			pickResult = new PickResult
			{
				document = document,
				pickedElement = visualElement,
				distance = distance2
			};
			pickResult.ComputeCollisionData(worldRay);
			return true;
		}

		public static bool PickElement3D(VisualElement element, Ray worldRay, out PickResult pickResult, bool acceptOutside = false)
		{
			UIDocument uIDocument = UIDocument.FindRootUIDocument(element);
			if (uIDocument == null)
			{
				throw new ArgumentException("Element must be part of a UI Document.");
			}
			Ray worldRay2 = uIDocument.transform.worldToLocalMatrix.TransformRay(worldRay);
			if (!element.IntersectWorldRay(worldRay2, out var distance, out var _) && (!acceptOutside || !(distance > 0f)))
			{
				pickResult = PickResult.Empty;
				return false;
			}
			pickResult = new PickResult
			{
				document = uIDocument,
				pickedElement = element,
				distance = distance
			};
			pickResult.ComputeCollisionData(worldRay);
			return true;
		}

		public static PickResult PickDocument3D(Ray worldRay, float maxDistance = float.PositiveInfinity, int layerMask = -5)
		{
			PickResult result = new PickResult
			{
				distance = float.PositiveInfinity
			};
			float num = 0f;
			Ray ray = worldRay;
			int num2 = 0;
			while (num < maxDistance)
			{
				if (++num2 > 100)
				{
					Debug.LogWarning("PickDocument3D exceeded iteration limit of " + 100 + ". Returned values may be incorrect.");
					break;
				}
				if (!Physics.Raycast(ray, out var hitInfo, maxDistance - num, layerMask, QueryTriggerInteraction.Collide))
				{
					break;
				}
				float distance = hitInfo.distance + num;
				UIDocument componentInParent = hitInfo.collider.GetComponentInParent<UIDocument>(includeInactive: true);
				if (componentInParent == null)
				{
					if (distance < result.distance)
					{
						result = new PickResult
						{
							distance = distance,
							collider = hitInfo.collider,
							normal = hitInfo.normal,
							point = hitInfo.point,
							localPoint = hitInfo.point
						};
					}
					break;
				}
				float num3 = hitInfo.distance + 0.001f;
				ray.origin += ray.direction * num3;
				num += num3;
				if (componentInParent.containerPanel == null)
				{
					continue;
				}
				Bounds picking3DLocalBounds = GetPicking3DLocalBounds(componentInParent.rootVisualElement);
				ref Matrix4x4 worldTransformRef = ref componentInParent.rootVisualElement.worldTransformRef;
				Vector3 point = worldTransformRef.MultiplyPoint3x4(picking3DLocalBounds.center);
				Vector3 vector = worldTransformRef.MultiplyVector(picking3DLocalBounds.size);
				Matrix4x4 localToWorldMatrix = componentInParent.transform.localToWorldMatrix;
				Vector3 b = worldTransformRef.MultiplyPoint3x4(point);
				Vector3 vector2 = localToWorldMatrix.MultiplyVector(vector);
				float num4 = Vector3.Distance(worldRay.origin, b) + vector2.magnitude / 2f + 0.001f;
				maxDistance = Mathf.Min(maxDistance, num + num4);
				if (!(distance >= result.distance))
				{
					VisualElement visualElement = Pick3D(componentInParent, worldRay, out distance);
					if (visualElement != null && distance <= maxDistance && distance < result.distance)
					{
						result = new PickResult
						{
							collider = hitInfo.collider,
							pickedElement = visualElement,
							document = componentInParent,
							distance = distance
						};
						result.ComputeCollisionData(worldRay);
					}
				}
			}
			return result;
		}

		internal static VisualElement Pick_Internal(UIDocument document, Ray documentRay, List<VisualElement> outResults = null)
		{
			document.containerPanel.ValidateLayout();
			VisualElement rootVisualElement = document.rootVisualElement;
			Ray ray = rootVisualElement.WorldToLocal(documentRay);
			return PerformPick(rootVisualElement, ray, null);
		}

		[VisibleToOtherModules(new string[] { "Assembly-CSharp-testable" })]
		internal static VisualElement PerformPick(VisualElement root, Ray ray, List<VisualElement> outResults)
		{
			return root.needs3DBounds ? PerformPick3D(root, ray, outResults) : PerformPick2D(root, ray, outResults);
		}

		private static VisualElement PerformPick2D(VisualElement root, Ray ray, List<VisualElement> outResults)
		{
			root.IntersectLocalRay(ray, out var localPoint);
			return PerformPick2D_LocalPoint(root, localPoint, outResults);
		}

		private static VisualElement PerformPick3D(VisualElement root, Ray ray, List<VisualElement> outResults)
		{
			if (root.resolvedStyle.display == DisplayStyle.None)
			{
				return null;
			}
			if (root.pickingMode == PickingMode.Ignore && root.hierarchy.childCount == 0)
			{
				return null;
			}
			if (!GetPicking3DLocalBounds(root).IntersectRay(ray))
			{
				return null;
			}
			Vector3 localPoint;
			bool flag = root.IntersectLocalRay(ray, out localPoint) && root.ContainsPoint(localPoint);
			if (!flag && root.ShouldClip())
			{
				return null;
			}
			VisualElement visualElement = null;
			int childCount = root.hierarchy.childCount;
			for (int num = childCount - 1; num >= 0; num--)
			{
				VisualElement visualElement2 = root.hierarchy[num];
				Ray ray2 = root.ChangeCoordinatesTo(visualElement2, ray);
				VisualElement visualElement3 = PerformPick(visualElement2, ray2, outResults);
				if (visualElement == null && visualElement3 != null)
				{
					if (outResults == null)
					{
						return visualElement3;
					}
					visualElement = visualElement3;
				}
			}
			if (root.visible && root.pickingMode == PickingMode.Position && flag)
			{
				outResults?.Add(root);
				if (visualElement == null)
				{
					visualElement = root;
				}
			}
			return visualElement;
		}

		private static VisualElement PerformPick2D_LocalPoint(VisualElement root, Vector3 localPoint, List<VisualElement> picked = null)
		{
			if (root.resolvedStyle.display == DisplayStyle.None)
			{
				return null;
			}
			if (root.pickingMode == PickingMode.Ignore && root.hierarchy.childCount == 0)
			{
				return null;
			}
			if (!root.boundingBox.Contains(localPoint))
			{
				return null;
			}
			bool flag = root.ContainsPoint(localPoint);
			if (!flag && root.ShouldClip())
			{
				return null;
			}
			VisualElement visualElement = null;
			int childCount = root.hierarchy.childCount;
			for (int num = childCount - 1; num >= 0; num--)
			{
				VisualElement visualElement2 = root.hierarchy[num];
				Vector2 vector = root.ChangeCoordinatesTo(visualElement2, localPoint);
				VisualElement visualElement3 = PerformPick2D_LocalPoint(visualElement2, vector, picked);
				if (visualElement == null && visualElement3 != null)
				{
					if (picked == null)
					{
						return visualElement3;
					}
					visualElement = visualElement3;
				}
			}
			if (root.visible && root.pickingMode == PickingMode.Position && flag)
			{
				picked?.Add(root);
				if (visualElement == null)
				{
					visualElement = root;
				}
			}
			return visualElement;
		}

		internal static Bounds GetPicking3DWorldBounds(VisualElement ve)
		{
			Bounds bounds = GetPicking3DLocalBounds(ve);
			VisualElement.TransformAlignedBounds(ref ve.worldTransformRef, ref bounds);
			return bounds;
		}

		internal static Bounds GetPicking3DLocalBounds(VisualElement ve)
		{
			if (ve.needs3DBounds)
			{
				return ve.localBoundsPicking3D;
			}
			Rect boundingBox = ve.boundingBox;
			return new Bounds(boundingBox.center, boundingBox.size);
		}

		public static Vector3 LocalPointToGameObjectWorldSpace(VisualElement element, Vector3 localPoint)
		{
			UIDocument uIDocument = UIDocument.FindRootUIDocument(element);
			if (uIDocument == null)
			{
				throw new ArgumentException("Element must be part of a UI Document.");
			}
			Vector3 position = element.LocalToWorld3D(localPoint);
			return uIDocument.transform.TransformPoint(position);
		}

		public static Vector3 LocalDeltaToGameObjectWorldSpace(VisualElement element, Vector3 localDelta)
		{
			return LocalPointToGameObjectWorldSpace(element, localDelta) - LocalPointToGameObjectWorldSpace(element, Vector3.zero);
		}

		public static Vector3 GameObjectWorldSpaceToLocalPoint(VisualElement element, Vector3 worldPoint)
		{
			UIDocument uIDocument = UIDocument.FindRootUIDocument(element);
			if (uIDocument == null)
			{
				throw new ArgumentException("Element must be part of a UI Document.");
			}
			Vector3 p = uIDocument.transform.InverseTransformPoint(worldPoint);
			return element.WorldToLocal3D(p);
		}

		public static Vector3 GameObjectWorldSpaceToLocalDelta(VisualElement element, Vector3 worldDelta)
		{
			return GameObjectWorldSpaceToLocalPoint(element, worldDelta) - GameObjectWorldSpaceToLocalPoint(element, Vector3.zero);
		}
	}
	internal static class GroupBoxUtility
	{
		private static Dictionary<IGroupBox, IGroupManager> s_GroupManagers = new Dictionary<IGroupBox, IGroupManager>();

		private static Dictionary<IGroupBoxOption, IGroupManager> s_GroupOptionManagerCache = new Dictionary<IGroupBoxOption, IGroupManager>();

		private static readonly Type k_GenericGroupBoxType = typeof(IGroupBox<>);

		public static void RegisterGroupBoxOption<T>(this T option) where T : VisualElement, IGroupBoxOption
		{
			IGroupBox groupBox = null;
			for (VisualElement parent = option.hierarchy.parent; parent != null; parent = parent.hierarchy.parent)
			{
				if (parent is IGroupBox groupBox2)
				{
					groupBox = groupBox2;
					break;
				}
			}
			IGroupBox groupBox3 = groupBox ?? option.elementPanel;
			IGroupManager groupManager = FindOrCreateGroupManager(groupBox3);
			groupManager.RegisterOption(option);
			s_GroupOptionManagerCache[option] = groupManager;
		}

		public static void UnregisterGroupBoxOption<T>(this T option) where T : VisualElement, IGroupBoxOption
		{
			if (s_GroupOptionManagerCache.ContainsKey(option))
			{
				s_GroupOptionManagerCache[option].UnregisterOption(option);
				s_GroupOptionManagerCache.Remove(option);
			}
		}

		public static void OnOptionSelected<T>(this T selectedOption) where T : VisualElement, IGroupBoxOption
		{
			if (s_GroupOptionManagerCache.ContainsKey(selectedOption))
			{
				s_GroupOptionManagerCache[selectedOption].OnOptionSelectionChanged(selectedOption);
			}
		}

		public static IGroupBoxOption GetSelectedOption(this IGroupBox groupBox)
		{
			return (!s_GroupManagers.ContainsKey(groupBox)) ? null : s_GroupManagers[groupBox].GetSelectedOption();
		}

		public static IGroupManager GetGroupManager(this IGroupBox groupBox)
		{
			return s_GroupManagers.ContainsKey(groupBox) ? s_GroupManagers[groupBox] : null;
		}

		private static IGroupManager FindOrCreateGroupManager(IGroupBox groupBox)
		{
			if (s_GroupManagers.ContainsKey(groupBox))
			{
				return s_GroupManagers[groupBox];
			}
			Type type = null;
			Type[] interfaces = groupBox.GetType().GetInterfaces();
			foreach (Type type2 in interfaces)
			{
				if (type2.IsGenericType && k_GenericGroupBoxType.IsAssignableFrom(type2.GetGenericTypeDefinition()))
				{
					type = type2.GetGenericArguments()[0];
					break;
				}
			}
			object obj;
			if (!(type != null))
			{
				IGroupManager groupManager = new DefaultGroupManager();
				obj = groupManager;
			}
			else
			{
				obj = (IGroupManager)Activator.CreateInstance(type);
			}
			IGroupManager groupManager2 = (IGroupManager)obj;
			groupManager2.Init(groupBox);
			if (groupBox is BaseVisualElementPanel baseVisualElementPanel)
			{
				baseVisualElementPanel.panelDisposed += OnPanelDestroyed;
			}
			else if (groupBox is VisualElement visualElement)
			{
				visualElement.RegisterCallback<DetachFromPanelEvent>(OnGroupBoxDetachedFromPanel);
			}
			s_GroupManagers[groupBox] = groupManager2;
			return groupManager2;
		}

		private static void OnGroupBoxDetachedFromPanel(DetachFromPanelEvent evt)
		{
			s_GroupManagers.Remove(evt.currentTarget as IGroupBox);
		}

		private static void OnPanelDestroyed(BaseVisualElementPanel panel)
		{
			s_GroupManagers.Remove(panel);
			panel.panelDisposed -= OnPanelDestroyed;
		}
	}
	[VisibleToOtherModules(new string[] { "UnityEditor.UIBuilderModule" })]
	internal static class IEnumerableExtensions
	{
		internal static bool HasValues(this IEnumerable<string> collection)
		{
			if (collection == null)
			{
				return false;
			}
			using (IEnumerator<string> enumerator = collection.GetEnumerator())
			{
				if (enumerator.MoveNext())
				{
					string current = enumerator.Current;
					return true;
				}
			}
			return false;
		}

		internal static bool NoElementOfTypeMatchesPredicate<T>(this IEnumerable collection, Func<T, bool> predicate)
		{
			foreach (object item in collection)
			{
				if (item is T arg && predicate(arg))
				{
					return false;
				}
			}
			return true;
		}

		[VisibleToOtherModules(new string[] { "UnityEditor.UIBuilderModule" })]
		internal static int GetCount(this IEnumerable collection)
		{
			int num = 0;
			foreach (object item in collection)
			{
				num++;
			}
			return num;
		}

		[VisibleToOtherModules(new string[] { "UnityEditor.UIBuilderModule" })]
		internal static bool Any<T>(this List<T> source, Func<T, bool> predicate)
		{
			foreach (T item in source)
			{
				if (predicate(item))
				{
					return true;
				}
			}
			return false;
		}
	}
