	internal class MeshGenerationNodeImpl : IDisposable
	{
		private GCHandle m_SelfHandle;

		private Entry m_ParentEntry;

		private EntryRecorder m_EntryRecorder;

		protected bool disposed { get; private set; }

		public MeshGenerationNodeImpl()
		{
			m_SelfHandle = GCHandle.Alloc(this);
		}

		public void Init(Entry parentEntry, EntryRecorder entryRecorder, bool safe)
		{
			Debug.Assert(m_ParentEntry == null);
			Debug.Assert(parentEntry != null);
			Debug.Assert(entryRecorder != null);
			m_ParentEntry = parentEntry;
			m_EntryRecorder = entryRecorder;
		}

		public void Reset()
		{
			Debug.Assert(m_ParentEntry != null);
			Debug.Assert(m_EntryRecorder != null);
			m_ParentEntry = null;
			m_EntryRecorder = null;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void GetNode(out MeshGenerationNode node)
		{
			MeshGenerationNode.Create(m_SelfHandle, out node);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void GetUnsafeNode(out UnsafeMeshGenerationNode node)
		{
			UnsafeMeshGenerationNode.Create(m_SelfHandle, out node);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public Entry GetParentEntry()
		{
			return m_ParentEntry;
		}

		public void DrawMesh(NativeSlice<Vertex> vertices, NativeSlice<ushort> indices, Texture texture = null, TextureOptions textureOptions = TextureOptions.None)
		{
			if (vertices.Length != 0 && indices.Length != 0)
			{
				m_EntryRecorder.DrawMesh(m_ParentEntry, vertices, indices, texture, textureOptions);
			}
		}

		public void DrawGradients(NativeSlice<Vertex> vertices, NativeSlice<ushort> indices, VectorImage gradientsOwner)
		{
			if (vertices.Length != 0 && indices.Length != 0 && !(gradientsOwner == null))
			{
				m_EntryRecorder.DrawGradients(m_ParentEntry, vertices, indices, gradientsOwner);
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected void Dispose(bool disposing)
		{
			if (disposed)
			{
				return;
			}
			if (disposing)
			{
				if (m_ParentEntry != null)
				{
					Reset();
				}
				m_SelfHandle.Free();
			}
			disposed = true;
		}
	}
	internal class MeshGenerationNodeManager : IDisposable
	{
		private List<MeshGenerationNodeImpl> m_Nodes = new List<MeshGenerationNodeImpl>(8);

		private int m_UsedCounter;

		private EntryRecorder m_EntryRecorder;

		protected bool disposed { get; private set; }

		public MeshGenerationNodeManager(EntryRecorder entryRecorder)
		{
			m_EntryRecorder = entryRecorder;
		}

		public void CreateNode(Entry parentEntry, out MeshGenerationNode node)
		{
			MeshGenerationNodeImpl meshGenerationNodeImpl = CreateImpl(parentEntry, safe: true);
			meshGenerationNodeImpl.GetNode(out node);
		}

		public void CreateUnsafeNode(Entry parentEntry, out UnsafeMeshGenerationNode node)
		{
			MeshGenerationNodeImpl meshGenerationNodeImpl = CreateImpl(parentEntry, safe: false);
			meshGenerationNodeImpl.GetUnsafeNode(out node);
		}

		private MeshGenerationNodeImpl CreateImpl(Entry parentEntry, bool safe)
		{
			if (disposed)
			{
				DisposeHelper.NotifyDisposedUsed(this);
				return null;
			}
			if (m_Nodes.Count == m_UsedCounter)
			{
				for (int i = 0; i < 200; i++)
				{
					m_Nodes.Add(new MeshGenerationNodeImpl());
				}
			}
			MeshGenerationNodeImpl meshGenerationNodeImpl = m_Nodes[m_UsedCounter++];
			meshGenerationNodeImpl.Init(parentEntry, m_EntryRecorder, safe);
			return meshGenerationNodeImpl;
		}

		public void ResetAll()
		{
			for (int i = 0; i < m_UsedCounter; i++)
			{
				m_Nodes[i].Reset();
			}
			m_UsedCounter = 0;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected void Dispose(bool disposing)
		{
			if (disposed)
			{
				return;
			}
			if (disposing)
			{
				int i = 0;
				for (int count = m_Nodes.Count; i < count; i++)
				{
					m_Nodes[i].Dispose();
				}
				m_Nodes.Clear();
			}
			disposed = true;
		}
	}
	public class Painter2D : IDisposable
	{
		private struct Painter2DJobData
		{
			public UnsafeMeshGenerationNode node;

			public int snapshotIndex;
		}

		private struct Painter2DJob : IJobParallelFor
		{
			[NativeDisableUnsafePtrRestriction]
			public IntPtr painterHandle;

			[ReadOnly]
			public TempMeshAllocator allocator;

			[ReadOnly]
			public NativeSlice<Painter2DJobData> jobParameters;

			public unsafe void Execute(int i)
			{
				Painter2DJobData painter2DJobData = jobParameters[i];
				MeshWriteDataInterface meshWriteDataInterface = UIPainter2D.ExecuteSnapshotFromJob(painterHandle, painter2DJobData.snapshotIndex);
				NativeSlice<Vertex> slice = UIRenderDevice.PtrToSlice<Vertex>((void*)meshWriteDataInterface.vertices, meshWriteDataInterface.vertexCount);
				NativeSlice<ushort> slice2 = UIRenderDevice.PtrToSlice<ushort>((void*)meshWriteDataInterface.indices, meshWriteDataInterface.indexCount);
				if (slice.Length != 0 && slice2.Length != 0)
				{
					allocator.AllocateTempMesh(slice.Length, slice2.Length, out var vertices, out var indices);
					Debug.Assert(vertices.Length == slice.Length);
					Debug.Assert(indices.Length == slice2.Length);
					vertices.CopyFrom(slice);
					indices.CopyFrom(slice2);
					painter2DJobData.node.DrawMesh(vertices, indices);
				}
			}
		}

		private MeshGenerationContext m_Ctx;

		internal DetachedAllocator m_DetachedAllocator;

		internal SafeHandleAccess m_Handle;

		private List<Painter2DJobData> m_JobSnapshots = null;

		private NativeArray<Painter2DJobData> m_JobParameters;

		private bool m_Disposed;

		private static readonly ProfilerMarker s_StrokeMarker = new ProfilerMarker("Painter2D.Stroke");

		private static readonly ProfilerMarker s_FillMarker = new ProfilerMarker("Painter2D.Fill");

		private MeshGenerationCallback m_OnMeshGenerationDelegate;

		internal bool isDetached => m_DetachedAllocator != null;

		public float lineWidth
