				int i;
				for (i = 0; i < physicalParent.m_Children.Count && physicalParent.m_Children[i] != visualElement; i++)
				{
				}
				if (i < physicalParent.m_Children.Count - 1)
				{
					return physicalParent.m_Children[i + 1];
