		{
			if (!HasAllocatedHyperlinkCallbacks())
			{
				m_HyperlinkOnPointerUp = HyperlinkOnPointerUp;
				m_HyperlinkOnPointerMove = HyperlinkOnPointerMove;
				m_HyperlinkOnPointerOver = HyperlinkOnPointerOver;
