	internal class TextEditingManipulator
	{
		private readonly TextElement m_TextElement;

		private TextEditorEventHandler m_EditingEventHandler;

		internal TextEditingUtilities editingUtilities;

		private bool m_TouchScreenTextFieldInitialized;

		private IVisualElementScheduledItem m_HardwareKeyboardPoller = null;

		internal TextEditorEventHandler editingEventHandler
		{
			get
			{
				return m_EditingEventHandler;
			}
			set
			{
				if (m_EditingEventHandler != value)
				{
					m_EditingEventHandler?.UnregisterCallbacksFromTarget(m_TextElement);
					m_EditingEventHandler = value;
					m_EditingEventHandler?.RegisterCallbacksOnTarget(m_TextElement);
				}
			}
		}

		private bool touchScreenTextFieldChanged => m_TouchScreenTextFieldInitialized != editingUtilities?.TouchScreenKeyboardShouldBeUsed();

		public TextEditingManipulator(TextElement textElement)
		{
			m_TextElement = textElement;
			editingUtilities = new TextEditingUtilities(textElement.selectingManipulator.m_SelectingUtilities, textElement.uitkTextHandle, textElement.text);
			InitTextEditorEventHandler();
		}

		public void Reset()
		{
			editingEventHandler = null;
		}

		private void InitTextEditorEventHandler()
		{
			m_TouchScreenTextFieldInitialized = editingUtilities?.TouchScreenKeyboardShouldBeUsed() ?? false;
			if (m_TouchScreenTextFieldInitialized)
			{
				editingEventHandler = new TouchScreenTextEditorEventHandler(m_TextElement, editingUtilities);
			}
			else
			{
				editingEventHandler = new KeyboardTextEditorEventHandler(m_TextElement, editingUtilities);
			}
		}

		internal void HandleEventBubbleUp(EventBase evt)
		{
			if (m_TextElement.edition.isReadOnly)
			{
				return;
			}
			if (evt is BlurEvent)
			{
				m_TextElement.uitkTextHandle.RemoveTextInfoFromPermanentCache();
			}
			else if ((!(evt is PointerMoveEvent) && !(evt is MouseMoveEvent)) || m_TextElement.selectingManipulator.isClicking)
			{
				m_TextElement.uitkTextHandle.AddToPermanentCacheAndGenerateMesh();
			}
			if (!(evt is FocusInEvent))
			{
				if (evt is FocusOutEvent)
				{
					OnFocusOutEvent();
				}
			}
			else
			{
				OnFocusInEvent();
			}
			editingEventHandler?.HandleEventBubbleUp(evt);
		}

		private void OnFocusInEvent()
		{
			m_TextElement.edition.SaveValueAndText();
			m_TextElement.focusController.selectedTextElement = m_TextElement;
			if (touchScreenTextFieldChanged)
			{
				InitTextEditorEventHandler();
			}
			if (m_HardwareKeyboardPoller == null)
			{
				m_HardwareKeyboardPoller = m_TextElement.schedule.Execute((Action)delegate
				{
					if (touchScreenTextFieldChanged)
					{
						InitTextEditorEventHandler();
						m_TextElement.Blur();
					}
				}).Every(250L);
			}
			else
			{
				m_HardwareKeyboardPoller.Resume();
			}
		}

		private void OnFocusOutEvent()
		{
			m_HardwareKeyboardPoller?.Pause();
			editingUtilities.OnBlur();
		}
	}
	public class TextElement : BindableElement, ITextElement, INotifyValueChanged<string>, ITextEdition, ITextElementExperimentalFeatures, IExperimentalFeatures, ITextSelection
	{
		public readonly struct Glyph
		{
			public readonly NativeSlice<Vertex> vertices;

			internal Glyph(NativeSlice<Vertex> vertices)
			{
				this.vertices = vertices;
			}
		}

		public readonly struct GlyphsEnumerable
		{
			public readonly int Count;

			private readonly List<NativeSlice<Vertex>> m_Vertices;

			private readonly TextElement m_TextElement;

			internal GlyphsEnumerable(TextElement te, List<NativeSlice<Vertex>> vertices)
			{
				m_TextElement = te;
				m_Vertices = vertices;
				Count = ComputeCount(vertices);
			}

			internal GlyphsEnumerable(TextElement te, List<NativeSlice<Vertex>> vertices, ATGMeshInfo[] meshInfos)
			{
				m_TextElement = te;
				m_Vertices = vertices;
				Count = ComputeCount(vertices);
				for (int i = 0; i < meshInfos.Length; i++)
				{
					ATGMeshInfo aTGMeshInfo = meshInfos[i];
					if (aTGMeshInfo.textElementInfoIndicesByAtlas.Count > 1)
					{
						Debug.LogWarning("PostProcessTextVertices with ATG does not support this Multi-Atlas.");
					}
				}
			}

			private static int ComputeCount(List<NativeSlice<Vertex>> verts)
			{
				int num = 0;
				for (int i = 0; i < verts.Count; i++)
				{
					num += verts[i].Length;
				}
				return num / 4;
			}

			public GlyphsEnumerator GetEnumerator()
			{
				return new GlyphsEnumerator(m_TextElement, m_Vertices);
			}
		}

		public struct GlyphsEnumerator
		{
			private readonly TextElement m_TextElement;

			private readonly List<NativeSlice<Vertex>> m_Vertices;

			private int m_NextIndex;

			public Glyph Current { get; private set; }

			internal GlyphsEnumerator(TextElement textElement, List<NativeSlice<Vertex>> vertices)
			{
				m_TextElement = textElement;
				m_Vertices = vertices;
				m_NextIndex = 0;
				Current = default(Glyph);
			}

			public bool MoveNext()
			{
				if (m_TextElement.computedStyle.unityTextGenerator == TextGeneratorType.Advanced)
				{
					return MoveNextAdvanced();
				}
				return MoveNextStandard();
			}

			private bool MoveNextStandard()
			{
				UnityEngine.TextCore.Text.TextInfo textInfo = m_TextElement.uitkTextHandle.textInfo;
				int characterCount = textInfo.characterCount;
				while (m_NextIndex < characterCount)
				{
					ref TextElementInfo reference = ref textInfo.textElementInfo[m_NextIndex++];
					if (!reference.isVisible)
					{
						continue;
					}
					Current = new Glyph(m_Vertices[reference.materialReferenceIndex].Slice(reference.vertexIndex, 4));
					return true;
				}
				return false;
			}

			private bool MoveNextAdvanced()
			{
				IntPtr textGenerationInfo = m_TextElement.uitkTextHandle.textGenerationInfo;
				int glyphCount = TextGenerationInfo.GetGlyphCount(textGenerationInfo);
				while (m_NextIndex < glyphCount)
				{
					TextRenderingIndices textRenderingIndices = TextGenerationInfo.GetTextRenderingIndices(textGenerationInfo, m_NextIndex++);
					if (textRenderingIndices.textElementInfoIndex < 0 || textRenderingIndices.meshIndex < 0)
					{
						continue;
					}
					Current = new Glyph(m_Vertices[textRenderingIndices.meshIndex].Slice(textRenderingIndices.textElementInfoIndex * 4, 4));
					return true;
				}
				return false;
			}

			public void Reset()
			{
				m_NextIndex = 0;
			}
		}

