				bool result = inputFieldAppearance switch
				{
					TouchScreenKeyboard.InputFieldAppearance.AlwaysHidden => true, 
					TouchScreenKeyboard.InputFieldAppearance.AlwaysVisible => false, 
					_ => m_HideMobileInput, 
