		internal bool showPlaceholderText
		{
			get
			{
				bool flag = m_PlaceholderText.Length > 0;
				bool flag2 = edition.hidePlaceholderOnFocus && hasFocus;
				bool result = string.IsNullOrEmpty(text);
				if (!flag)
				{
					return false;
				}
				if (flag2)
				{
					return false;
				}
				return result;
			}
		}

