			}
			Vector2 point = new Vector2(rect.xMin, rect.yMin);
			Vector2 point2 = new Vector2(rect.xMax, rect.yMax);
			Vector2 point3 = new Vector2(rect.xMax, rect.yMin);
			Vector2 point4 = new Vector2(rect.xMin, rect.yMax);
