	public struct VisualElementStyleSheetSet : IEquatable<VisualElementStyleSheetSet>
	{
		private readonly VisualElement m_Element;

		public int count
		{
			get
			{
				if (m_Element.styleSheetList == null)
				{
					return 0;
				}
				return m_Element.styleSheetList.Count;
			}
		}

		public StyleSheet this[int index]
		{
			get
			{
				if (m_Element.styleSheetList == null)
				{
					throw new ArgumentOutOfRangeException("index");
				}
				return m_Element.styleSheetList[index];
			}
		}

		internal VisualElementStyleSheetSet(VisualElement element)
		{
			m_Element = element;
		}

		public void Add(StyleSheet styleSheet)
		{
			Insert(count, styleSheet);
		}

		public void Insert(int index, StyleSheet styleSheet)
		{
			if (styleSheet == null)
			{
				throw new ArgumentNullException("styleSheet");
			}
			if (m_Element.styleSheetList == null)
			{
				m_Element.styleSheetList = new List<StyleSheet>();
			}
			else if (m_Element.styleSheetList.Contains(styleSheet))
			{
				return;
			}
			m_Element.styleSheetList.Insert(index, styleSheet);
			m_Element.IncrementVersion(VersionChangeType.StyleSheet);
		}

		public void Clear()
		{
			if (m_Element.styleSheetList != null)
			{
				m_Element.styleSheetList = null;
				m_Element.IncrementVersion(VersionChangeType.StyleSheet);
			}
		}

		public bool Remove(StyleSheet styleSheet)
		{
			if (styleSheet == null)
			{
				throw new ArgumentNullException("styleSheet");
			}
			if (m_Element.styleSheetList != null && m_Element.styleSheetList.Remove(styleSheet))
			{
				if (m_Element.styleSheetList.Count == 0)
				{
					m_Element.styleSheetList = null;
				}
				m_Element.IncrementVersion(VersionChangeType.StyleSheet);
				return true;
			}
			return false;
		}

		internal void Swap(StyleSheet old, StyleSheet @new)
		{
			if (old == null)
			{
				throw new ArgumentNullException("old");
			}
			if (@new == null)
			{
				throw new ArgumentNullException("new");
			}
			if (m_Element.styleSheetList != null)
			{
				int num = m_Element.styleSheetList.IndexOf(old);
				if (num >= 0)
				{
					m_Element.IncrementVersion(VersionChangeType.StyleSheet);
					m_Element.styleSheetList[num] = @new;
				}
			}
		}

		public bool Contains(StyleSheet styleSheet)
		{
			if (styleSheet == null)
			{
				throw new ArgumentNullException("styleSheet");
			}
			if (m_Element.styleSheetList != null)
			{
				return m_Element.styleSheetList.Contains(styleSheet);
			}
			return false;
		}

		public bool Equals(VisualElementStyleSheetSet other)
		{
			return object.Equals(m_Element, other.m_Element);
		}

		public override bool Equals(object obj)
		{
			if (obj == null)
			{
				return false;
			}
			return obj is VisualElementStyleSheetSet && Equals((VisualElementStyleSheetSet)obj);
		}

		public override int GetHashCode()
		{
			return (m_Element != null) ? m_Element.GetHashCode() : 0;
		}

		public static bool operator ==(VisualElementStyleSheetSet left, VisualElementStyleSheetSet right)
		{
			return left.Equals(right);
		}

		public static bool operator !=(VisualElementStyleSheetSet left, VisualElementStyleSheetSet right)
		{
			return !left.Equals(right);
		}
	}
	internal static class VisualElementUtils
	{
		private static readonly HashSet<string> s_usedNames = new HashSet<string>();

		private static readonly Type s_FoldoutType = typeof(Foldout);

		private static readonly string s_InspectorElementUssClassName = "unity-inspector-element";

		public static string GetUniqueName(string nameBase)
		{
			string text = nameBase;
			int num = 2;
			while (s_usedNames.Contains(text))
			{
				text = nameBase + num;
				num++;
			}
			s_usedNames.Add(text);
			return text;
		}

		internal static int GetFoldoutDepth(this VisualElement element)
		{
			int num = 0;
			if (element.parent != null)
			{
				for (VisualElement parent = element.parent; parent != null; parent = parent.parent)
				{
					if (s_FoldoutType.IsAssignableFrom(parent.GetType()))
					{
						num++;
					}
				}
			}
			return num;
		}

		internal static void AssignInspectorStyleIfNecessary(this VisualElement element, string classNameToEnable)
		{
			VisualElement firstAncestorWhere = element.GetFirstAncestorWhere((VisualElement i) => i.ClassListContains(s_InspectorElementUssClassName));
			element.EnableInClassList(classNameToEnable, firstAncestorWhere != null);
		}
	}
	internal class VisualElementAnimationSystem : BaseVisualTreeUpdater
	{
		private HashSet<IValueAnimationUpdate> m_Animations = new HashSet<IValueAnimationUpdate>();

		private List<IValueAnimationUpdate> m_IterationList = new List<IValueAnimationUpdate>();

		private bool m_HasNewAnimations = false;

		private bool m_IterationListDirty = false;

		private static readonly string s_Description = "UIElements.UpdateAnimation";

		private static readonly ProfilerMarker s_ProfilerMarker = new ProfilerMarker(s_Description);

		private static readonly string s_StylePropertyAnimationDescription = "UIElements.UpdateAnimationProperties";

		private static readonly ProfilerMarker s_StylePropertyAnimationProfilerMarker = new ProfilerMarker(s_StylePropertyAnimationDescription);

		private long lastUpdate;

		public override ProfilerMarker profilerMarker => s_ProfilerMarker;

		private static ProfilerMarker stylePropertyAnimationProfilerMarker => s_StylePropertyAnimationProfilerMarker;

		private long CurrentTimeMs()
		{
			return Panel.TimeSinceStartupMs();
		}

		public void UnregisterAnimation(IValueAnimationUpdate anim)
		{
			m_Animations.Remove(anim);
			m_IterationListDirty = true;
		}

		public void UnregisterAnimations(List<IValueAnimationUpdate> anims)
		{
			foreach (IValueAnimationUpdate anim in anims)
			{
				m_Animations.Remove(anim);
			}
			m_IterationListDirty = true;
		}

		public void RegisterAnimation(IValueAnimationUpdate anim)
		{
			m_Animations.Add(anim);
			m_HasNewAnimations = true;
			m_IterationListDirty = true;
		}

		public void RegisterAnimations(List<IValueAnimationUpdate> anims)
		{
			foreach (IValueAnimationUpdate anim in anims)
			{
				m_Animations.Add(anim);
			}
			m_HasNewAnimations = true;
			m_IterationListDirty = true;
		}

		public override void Update()
		{
			long num = Panel.TimeSinceStartupMs();
			if (m_IterationListDirty)
			{
				m_IterationList = m_Animations.ToList();
				m_IterationListDirty = false;
			}
			if (m_HasNewAnimations || lastUpdate != num)
			{
				foreach (IValueAnimationUpdate iteration in m_IterationList)
				{
					iteration.Tick(num);
				}
				m_HasNewAnimations = false;
				lastUpdate = num;
			}
			IStylePropertyAnimationSystem styleAnimationSystem = base.panel.styleAnimationSystem;
			using (stylePropertyAnimationProfilerMarker.Auto())
			{
				styleAnimationSystem.Update();
			}
		}

		public override void OnVersionChanged(VisualElement ve, VersionChangeType versionChangeType)
		{
		}
	}
	internal class VisualTreeHierarchyFlagsUpdater : BaseVisualTreeUpdater
	{
		private uint m_Version = 0u;

		private uint m_LastVersion = 0u;

		private static readonly string s_Description = "UIElements.UpdateElementBounds";

		private static readonly ProfilerMarker s_ProfilerMarker = new ProfilerMarker(s_Description);

		private const VersionChangeType WorldTransformChanged = VersionChangeType.Transform;

		private const VersionChangeType WorldClipChanged = VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size;

		private const VersionChangeType EventParentCategoriesChanged = VersionChangeType.Hierarchy | VersionChangeType.EventCallbackCategories;

		protected const VersionChangeType BoundingBoxChanged = VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.Transform | VersionChangeType.Size;

		protected const VersionChangeType ChildrenChanged = VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size | VersionChangeType.EventCallbackCategories;

		protected const VersionChangeType VersionChanged = VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size | VersionChangeType.Picking;

		protected const VersionChangeType AnythingChanged = VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size | VersionChangeType.EventCallbackCategories | VersionChangeType.Picking;

		protected const VisualElementFlags BoundingBoxDirtyFlags = VisualElementFlags.BoundingBoxDirty | VisualElementFlags.WorldBoundingBoxDirty | VisualElementFlags.BoundingBoxDirtiedSinceLastLayoutPass;

		public override ProfilerMarker profilerMarker => s_ProfilerMarker;

		public override void OnVersionChanged(VisualElement ve, VersionChangeType versionChangeType)
		{
			if ((versionChangeType & (VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size | VersionChangeType.EventCallbackCategories | VersionChangeType.Picking)) != 0)
			{
				if ((versionChangeType & (VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size | VersionChangeType.EventCallbackCategories)) != 0)
				{
					DirtyChildrenHierarchy(ve, GetChildrenMustDirtyFlags(ve, versionChangeType));
				}
				if ((versionChangeType & (VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.Transform | VersionChangeType.Size)) != 0)
				{
					DirtyBoundingBoxHierarchy(ve);
				}
				if ((versionChangeType & (VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size | VersionChangeType.Picking)) != 0)
				{
					m_Version++;
				}
			}
		}

		protected static VisualElementFlags GetChildrenMustDirtyFlags(VisualElement ve, VersionChangeType versionChangeType)
		{
			VisualElementFlags visualElementFlags = (VisualElementFlags)0;
			if ((versionChangeType & VersionChangeType.Transform) != 0)
			{
				visualElementFlags |= VisualElementFlags.WorldTransformDirty | VisualElementFlags.WorldBoundingBoxDirty;
			}
			if ((versionChangeType & (VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size)) != 0)
			{
				visualElementFlags |= VisualElementFlags.WorldClipDirty;
			}
			if ((versionChangeType & (VersionChangeType.Hierarchy | VersionChangeType.EventCallbackCategories)) != 0)
			{
				visualElementFlags |= VisualElementFlags.EventInterestParentCategoriesDirty;
			}
			return visualElementFlags;
		}

		protected static void DirtyChildrenHierarchy(VisualElement ve, VisualElementFlags mustDirtyFlags)
		{
			VisualElementFlags visualElementFlags = mustDirtyFlags & ~ve.flags;
			if (visualElementFlags != 0)
			{
				ve.flags |= visualElementFlags;
				int childCount = ve.hierarchy.childCount;
				for (int i = 0; i < childCount; i++)
				{
					VisualElement ve2 = ve.hierarchy[i];
					DirtyChildrenHierarchy(ve2, visualElementFlags);
				}
			}
		}

		private static void DirtyBoundingBoxHierarchy(VisualElement ve)
		{
			ve.flags |= VisualElementFlags.BoundingBoxDirty | VisualElementFlags.WorldBoundingBoxDirty | VisualElementFlags.BoundingBoxDirtiedSinceLastLayoutPass;
			DirtyParentHierarchy(ve.hierarchy.parent, VisualElementFlags.BoundingBoxDirty | VisualElementFlags.WorldBoundingBoxDirty | VisualElementFlags.BoundingBoxDirtiedSinceLastLayoutPass);
		}

		private static void DirtyParentHierarchy(VisualElement ve, VisualElementFlags flags)
		{
			while (ve != null && (ve.flags & flags) != flags)
			{
				ve.flags |= flags;
				ve = ve.hierarchy.parent;
			}
		}

		public override void Update()
		{
			if (m_Version != m_LastVersion)
			{
				m_LastVersion = m_Version;
				base.panel.visualTree.UpdateBoundingBox();
				if (base.panel.UpdateElementUnderPointers() && base.panel.contextType == ContextType.Editor)
				{
					base.panel.ApplyStyles();
				}
			}
		}
	}
	internal class VisualTreeWorldSpaceHierarchyFlagsUpdater : VisualTreeHierarchyFlagsUpdater
	{
		private new const VisualElementFlags BoundingBoxDirtyFlags = VisualElementFlags.BoundingBoxDirty | VisualElementFlags.WorldBoundingBoxDirty | VisualElementFlags.LocalBounds3DDirty | VisualElementFlags.LocalBoundsWithoutNested3DDirty | VisualElementFlags.BoundingBoxDirtiedSinceLastLayoutPass;

		public override void OnVersionChanged(VisualElement ve, VersionChangeType versionChangeType)
		{
			if ((versionChangeType & (VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size | VersionChangeType.EventCallbackCategories | VersionChangeType.Picking)) != 0)
			{
				if ((versionChangeType & (VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.BorderWidth | VersionChangeType.Transform | VersionChangeType.Size | VersionChangeType.EventCallbackCategories)) != 0)
				{
					VisualTreeHierarchyFlagsUpdater.DirtyChildrenHierarchy(ve, VisualTreeHierarchyFlagsUpdater.GetChildrenMustDirtyFlags(ve, versionChangeType));
				}
				if ((versionChangeType & (VersionChangeType.Hierarchy | VersionChangeType.Overflow | VersionChangeType.Transform | VersionChangeType.Size)) != 0)
				{
					DirtyBoundingBoxHierarchy(ve);
				}
			}
		}

		private static VisualElementFlags GetParentMustDirtyFlags(VisualElement ve)
		{
			VisualElementFlags visualElementFlags = VisualElementFlags.BoundingBoxDirty | VisualElementFlags.WorldBoundingBoxDirty | VisualElementFlags.LocalBounds3DDirty | VisualElementFlags.LocalBoundsWithoutNested3DDirty | VisualElementFlags.BoundingBoxDirtiedSinceLastLayoutPass;
			if (ve.has3DTransform)
			{
				visualElementFlags |= VisualElementFlags.Needs3DBounds;
			}
			return visualElementFlags;
		}

		private static void DirtyBoundingBoxHierarchy(VisualElement ve)
		{
			VisualElementFlags visualElementFlags = GetParentMustDirtyFlags(ve);
			ve.flags |= visualElementFlags;
			if (ve is UIDocumentRootElement)
			{
				visualElementFlags &= ~VisualElementFlags.LocalBoundsWithoutNested3DDirty;
			}
			DirtyParentHierarchy(ve.hierarchy.parent, visualElementFlags);
		}

		private static void DirtyParentHierarchy(VisualElement ve, VisualElementFlags flags)
		{
			while (ve != null && (ve.flags & flags) != flags)
			{
				ve.flags |= flags;
				if (ve is UIDocumentRootElement)
				{
					flags &= ~VisualElementFlags.LocalBoundsWithoutNested3DDirty;
				}
				ve = ve.hierarchy.parent;
			}
		}

		public override void Update()
		{
		}
	}
	internal enum HierarchyChangeType
	{
		AddedToParent,
		RemovedFromParent,
		ChildrenReordered,
		AttachedToPanel,
		DetachedFromPanel
	}
	internal abstract class BaseVisualTreeHierarchyTrackerUpdater : BaseVisualTreeUpdater
	{
		private enum State
		{
			Waiting,
			TrackingAddOrMove,
			TrackingRemove
		}

		private State m_State = State.Waiting;

		private VisualElement m_CurrentChangeElement;

		private VisualElement m_CurrentChangeParent;

		protected abstract void OnHierarchyChange(VisualElement ve, HierarchyChangeType type);

		internal abstract void PollElementsWithBindings(Action<VisualElement, IBinding> callback);

		public override void OnVersionChanged(VisualElement ve, VersionChangeType versionChangeType)
		{
			if ((versionChangeType & VersionChangeType.Hierarchy) == VersionChangeType.Hierarchy)
			{
				switch (m_State)
				{
				case State.Waiting:
					ProcessNewChange(ve);
					break;
				case State.TrackingRemove:
					ProcessRemove(ve);
					break;
				case State.TrackingAddOrMove:
					ProcessAddOrMove(ve);
					break;
				}
			}
		}

		public override void Update()
		{
			Debug.Assert(m_State == State.TrackingAddOrMove || m_State == State.Waiting);
			if (m_State == State.TrackingAddOrMove)
			{
				OnHierarchyChange(m_CurrentChangeElement, HierarchyChangeType.ChildrenReordered);
				m_State = State.Waiting;
			}
			m_CurrentChangeElement = null;
			m_CurrentChangeParent = null;
		}

		private void ProcessNewChange(VisualElement ve)
		{
			m_CurrentChangeElement = ve;
			m_CurrentChangeParent = ve.parent;
			if (m_CurrentChangeParent == null && ve.panel != null)
			{
				OnHierarchyChange(m_CurrentChangeElement, HierarchyChangeType.ChildrenReordered);
				m_State = State.Waiting;
			}
			else
			{
				m_State = ((m_CurrentChangeParent != null) ? State.TrackingAddOrMove : State.TrackingRemove);
			}
		}

		private void ProcessAddOrMove(VisualElement ve)
		{
			Debug.Assert(m_CurrentChangeParent != null);
			if (m_CurrentChangeParent == ve)
			{
				OnHierarchyChange(m_CurrentChangeElement, HierarchyChangeType.AddedToParent);
				m_State = State.Waiting;
			}
			else
			{
				OnHierarchyChange(m_CurrentChangeElement, HierarchyChangeType.ChildrenReordered);
				ProcessNewChange(ve);
			}
		}

		private void ProcessRemove(VisualElement ve)
		{
			OnHierarchyChange(m_CurrentChangeElement, HierarchyChangeType.RemovedFromParent);
			if (ve.panel != null)
			{
				m_CurrentChangeParent = null;
				m_CurrentChangeElement = null;
				m_State = State.Waiting;
			}
			else
			{
				m_CurrentChangeElement = ve;
			}
		}
	}
