	}
	internal sealed class VisualTreeUpdater : IDisposable
	{
		private class UpdaterArray
		{
			private IVisualTreeUpdater[] m_VisualTreeUpdaters;

			public IVisualTreeUpdater this[VisualTreeUpdatePhase phase]
			{
				get
				{
