					}
				}
			}
			if (rectParams.backgroundRepeatInstanceList != null && num18 > 0)
			{
				rectParams.backgroundRepeatInstanceListEndIndex = m_BackgroundRepeatInstanceList.GetCount();
				DrawRectangle(rectParams);
			}
		}

		private void StampRectangleWithSubRect(RectangleParams rectParams, Rect targetRect, Rect totalRect, Rect targetUV, ref NativePagedList<BackgroundRepeatInstance> backgroundRepeatInstanceList)
		{
			if (targetRect.width < 0.001f || targetRect.height < 0.001f)
			{
				return;
			}
			Rect rect = targetRect;
			rect.size /= targetUV.size;
			rect.position -= new Vector2(targetUV.position.x, 1f - targetUV.position.y - targetUV.size.y) * rect.size;
			Rect subRect = rectParams.subRect;
			subRect.position *= rect.size;
			subRect.position += rect.position;
			subRect.size *= rect.size;
			if (rectParams.HasSlices(0.001f))
			{
				rectParams.backgroundRepeatRect = Rect.zero;
				rectParams.rect = targetRect;
			}
			else
			{
				Rect rect2 = RectangleParams.RectIntersection(subRect, targetRect);
				if (rect2.size.x < 0.001f || rect2.size.y < 0.001f)
				{
					return;
				}
				if (rect2.size != subRect.size)
				{
					Vector2 vector = rect2.size / subRect.size;
					Vector2 vector2 = rectParams.uv.size * vector;
					Vector2 vector3 = rectParams.uv.size - vector2;
					if (rect2.x > subRect.x)
					{
						float num = (subRect.xMax - rect2.xMax) / subRect.width * rectParams.uv.size.x;
						rectParams.uv.x += vector3.x - num;
					}
					if (rect2.yMax < subRect.yMax)
					{
						float num2 = (rect2.y - subRect.y) / subRect.height * rectParams.uv.size.y;
						rectParams.uv.y += vector3.y - num2;
					}
					rectParams.uv.size = vector2;
				}
				if (rectParams.vectorImage != null)
				{
					rectParams.backgroundRepeatRect = Rect.zero;
					rectParams.rect = rect2;
				}
				else
				{
					if (totalRect == rect2)
					{
						rectParams.backgroundRepeatRect = Rect.zero;
					}
					else
					{
						rectParams.backgroundRepeatRect = rect2;
					}
					rectParams.rect = totalRect;
				}
			}
			if (rectParams.vectorImage == null && backgroundRepeatInstanceList != null)
			{
				BackgroundRepeatInstance data = default(BackgroundRepeatInstance);
				data.rect = rectParams.rect;
				data.backgroundRepeatRect = rectParams.backgroundRepeatRect;
				data.uv = rectParams.uv;
				backgroundRepeatInstanceList.Add(data);
			}
			else
			{
				DrawRectangle(rectParams);
			}
		}

		private static void AdjustSpriteWinding(Vector2[] vertices, ushort[] indices, NativeSlice<ushort> newIndices)
		{
			for (int i = 0; i < indices.Length; i += 3)
			{
				Vector3 vector = vertices[indices[i]];
				Vector3 vector2 = vertices[indices[i + 1]];
				Vector3 vector3 = vertices[indices[i + 2]];
				Vector3 normalized = (vector2 - vector).normalized;
				Vector3 normalized2 = (vector3 - vector).normalized;
				if (Vector3.Cross(normalized, normalized2).z >= 0f)
				{
					newIndices[i] = indices[i + 1];
					newIndices[i + 1] = indices[i];
					newIndices[i + 2] = indices[i + 2];
				}
				else
				{
					newIndices[i] = indices[i];
					newIndices[i + 1] = indices[i + 1];
					newIndices[i + 2] = indices[i + 2];
				}
			}
		}

		public void ScheduleJobs(MeshGenerationContext mgc)
		{
			int count = m_TesselationJobParameters.Count;
			if (count != 0)
			{
				if (m_JobParameters.Length < count)
				{
					m_JobParameters.Dispose();
					m_JobParameters = new NativeArray<TessellationJobParameters>(count, Allocator.Persistent, NativeArrayOptions.UninitializedMemory);
				}
				for (int i = 0; i < count; i++)
				{
					m_JobParameters[i] = m_TesselationJobParameters[i];
				}
				m_TesselationJobParameters.Clear();
				TessellationJob jobData = new TessellationJob
				{
					jobParameters = m_JobParameters.Slice(0, count)
				};
				mgc.GetTempMeshAllocator(out jobData.allocator);
				JobHandle jobHandle = jobData.ScheduleOrRunJob(count, 1);
				mgc.AddMeshGenerationJob(jobHandle);
				mgc.AddMeshGenerationCallback(m_OnMeshGenerationDelegate, null, MeshGenerationCallbackType.Work, isJobDependent: true);
			}
		}

		private void OnMeshGeneration(MeshGenerationContext ctx, object data)
		{
			if (m_BackgroundRepeatInstanceList != null)
			{
				m_BackgroundRepeatInstanceList.Reset();
			}
			m_GCHandlePool.ReturnAll();
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		private void Dispose(bool disposing)
		{
			if (disposed)
			{
				return;
			}
			if (disposing)
			{
				if (m_BackgroundRepeatInstanceList != null)
				{
					m_BackgroundRepeatInstanceList.Dispose();
				}
				m_GCHandlePool.Dispose();
				m_JobParameters.Dispose();
			}
			disposed = true;
		}
	}
	internal class NativeList<T> : IDisposable where T : struct
	{
		private NativeArray<T> m_NativeArray;

		private int m_Count;

		public int Count => m_Count;

		protected bool disposed { get; private set; }

		public NativeList(int initialCapacity)
		{
			Debug.Assert(initialCapacity > 0);
			m_NativeArray = new NativeArray<T>(initialCapacity, Allocator.Persistent, NativeArrayOptions.UninitializedMemory);
		}

		public NativeList(int initialCapacity, Allocator allocator)
		{
			Debug.Assert(initialCapacity > 0);
			m_NativeArray = new NativeArray<T>(initialCapacity, allocator, NativeArrayOptions.UninitializedMemory);
		}

		private void Expand(int newLength)
		{
			NativeArray<T> nativeArray = new NativeArray<T>(newLength, Allocator.Persistent, NativeArrayOptions.UninitializedMemory);
			nativeArray.Slice(0, m_Count).CopyFrom(m_NativeArray);
			m_NativeArray.Dispose();
			m_NativeArray = nativeArray;
		}

		public void Add(ref T data)
		{
			if (m_Count == m_NativeArray.Length)
			{
				Expand(m_NativeArray.Length << 1);
			}
			m_NativeArray[m_Count++] = data;
		}

		public void Add(NativeSlice<T> src)
		{
			int num = m_Count + src.Length;
			if (m_NativeArray.Length < num)
			{
				Expand(num << 1);
			}
			m_NativeArray.Slice(m_Count, src.Length).CopyFrom(src);
			m_Count += src.Length;
		}

		public void Clear()
		{
			m_Count = 0;
		}

		public NativeSlice<T> GetSlice(int start, int length)
		{
			return m_NativeArray.Slice(start, length);
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected void Dispose(bool disposing)
		{
			if (!disposed)
			{
				if (disposing)
				{
					m_NativeArray.Dispose();
				}
				disposed = true;
			}
		}
	}
	internal class NativePagedList<T> : IDisposable where T : struct
	{
		public struct Enumerator
		{
			private NativePagedList<T> m_NativePagedList;

			private NativeArray<T> m_CurrentPage;

			private int m_IndexInCurrentPage;

			private int m_IndexOfCurrentPage;

			private int m_CountInCurrentPage;

			public Enumerator(NativePagedList<T> nativePagedList, int offset)
			{
				m_IndexInCurrentPage = 0;
				m_IndexOfCurrentPage = 0;
				m_CountInCurrentPage = 0;
				m_NativePagedList = nativePagedList;
				for (int i = 0; i < m_NativePagedList.m_Pages.Count - 1; i++)
				{
					m_CountInCurrentPage = m_NativePagedList.m_Pages[i].Length;
					if (offset >= m_CountInCurrentPage)
					{
						offset -= m_CountInCurrentPage;
						continue;
					}
					m_IndexInCurrentPage = offset;
					m_IndexOfCurrentPage = i;
					m_CurrentPage = m_NativePagedList.m_Pages[m_IndexOfCurrentPage];
					return;
				}
				m_IndexOfCurrentPage = m_NativePagedList.m_Pages.Count - 1;
				m_CountInCurrentPage = m_NativePagedList.m_CountInLastPage;
				m_IndexInCurrentPage = offset;
				m_CurrentPage = m_NativePagedList.m_LastPage;
			}

			public bool HasNext()
			{
				return m_IndexInCurrentPage < m_CountInCurrentPage;
			}

			public T GetNext()
			{
				if (!HasNext())
				{
					throw new InvalidOperationException("No more elements");
				}
				T result = m_CurrentPage[m_IndexInCurrentPage];
				m_IndexInCurrentPage++;
				if (m_IndexInCurrentPage == m_CountInCurrentPage)
				{
					m_IndexInCurrentPage = 0;
					m_IndexOfCurrentPage++;
					int count = m_NativePagedList.m_Pages.Count;
					if (m_IndexOfCurrentPage < count)
					{
						if (m_IndexOfCurrentPage < count - 1)
						{
							m_CountInCurrentPage = m_NativePagedList.m_Pages[m_IndexOfCurrentPage].Length;
						}
						else
						{
							m_CountInCurrentPage = m_NativePagedList.m_CountInLastPage;
						}
					}
					else
					{
						m_IndexOfCurrentPage = count - 1;
						m_CountInCurrentPage = m_NativePagedList.m_CountInLastPage;
						m_IndexInCurrentPage = m_CountInCurrentPage;
					}
					m_CurrentPage = m_NativePagedList.m_Pages[m_IndexOfCurrentPage];
				}
				return result;
			}
		}

		private readonly int k_PoolCapacity;

		private List<NativeArray<T>> m_Pages = new List<NativeArray<T>>(8);

		private NativeArray<T> m_LastPage;

		private int m_CountInLastPage;

		private Allocator m_FirstPageAllocator;

		private Allocator m_OtherPagesAllocator;

		private List<NativeSlice<T>> m_Enumerator = new List<NativeSlice<T>>(8);

		protected bool disposed { get; private set; }

		public NativePagedList(int poolCapacity, Allocator firstPageAllocator = Allocator.Persistent, Allocator otherPagesAllocator = Allocator.Persistent)
		{
			Debug.Assert(poolCapacity > 0);
			k_PoolCapacity = Mathf.NextPowerOfTwo(poolCapacity);
			m_FirstPageAllocator = firstPageAllocator;
			m_OtherPagesAllocator = otherPagesAllocator;
		}

		public void Add(ref T data)
		{
			if (m_CountInLastPage < m_LastPage.Length)
			{
				m_LastPage[m_CountInLastPage++] = data;
				return;
			}
			int length = ((m_Pages.Count > 0) ? (m_LastPage.Length << 1) : k_PoolCapacity);
			Allocator allocator = ((m_Pages.Count == 0) ? m_FirstPageAllocator : m_OtherPagesAllocator);
			m_LastPage = new NativeArray<T>(length, allocator, NativeArrayOptions.UninitializedMemory);
			m_Pages.Add(m_LastPage);
			m_LastPage[0] = data;
			m_CountInLastPage = 1;
		}

		public void Add(T data)
		{
			Add(ref data);
		}

		public List<NativeSlice<T>> GetPages()
		{
			m_Enumerator.Clear();
			if (m_Pages.Count > 0)
			{
				int num = m_Pages.Count - 1;
				for (int i = 0; i < num; i++)
				{
					m_Enumerator.Add(m_Pages[i]);
				}
				if (m_CountInLastPage > 0)
				{
					m_Enumerator.Add(m_LastPage.Slice(0, m_CountInLastPage));
				}
			}
			return m_Enumerator;
		}

		public int GetCount()
		{
			int num = m_CountInLastPage;
			for (int i = 0; i < m_Pages.Count - 1; i++)
			{
				num += m_Pages[i].Length;
			}
			return num;
		}

		public void Reset()
		{
			if (m_Pages.Count > 1)
			{
				m_LastPage = m_Pages[0];
				for (int i = 1; i < m_Pages.Count; i++)
				{
					m_Pages[i].Dispose();
				}
				m_Pages.Clear();
				m_Pages.Add(m_LastPage);
			}
			m_CountInLastPage = 0;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected void Dispose(bool disposing)
		{
			if (disposed)
			{
				return;
			}
			if (disposing)
			{
				for (int i = 0; i < m_Pages.Count; i++)
				{
					m_Pages[i].Dispose();
				}
				m_Pages.Clear();
				m_CountInLastPage = 0;
			}
			disposed = true;
		}
	}
	internal class OpacityIdAccelerator : IDisposable
	{
		private struct OpacityIdUpdateJob : IJobParallelFor
		{
			[NativeDisableContainerSafetyRestriction]
			public NativeSlice<Vertex> oldVerts;

			[NativeDisableContainerSafetyRestriction]
			public NativeSlice<Vertex> newVerts;

			public Color32 opacityData;

			public void Execute(int i)
			{
				Vertex value = oldVerts[i];
				value.opacityColorPages.r = opacityData.r;
				value.opacityColorPages.g = opacityData.g;
				value.ids.b = opacityData.b;
				newVerts[i] = value;
			}
		}

		private const int k_VerticesPerBatch = 128;

		private const int k_JobLimit = 256;

		private NativeArray<JobHandle> m_Jobs = new NativeArray<JobHandle>(256, Allocator.Persistent, NativeArrayOptions.UninitializedMemory);

		private int m_NextJobIndex;

		protected bool disposed { get; private set; }

		public void CreateJob(NativeSlice<Vertex> oldVerts, NativeSlice<Vertex> newVerts, Color32 opacityData, int vertexCount)
		{
			JobHandle value = new OpacityIdUpdateJob
			{
				oldVerts = oldVerts,
				newVerts = newVerts,
				opacityData = opacityData
			}.ScheduleOrRunJob(vertexCount, 128);
			if (m_NextJobIndex == m_Jobs.Length)
			{
				m_Jobs[0] = JobHandle.CombineDependencies(m_Jobs);
				m_NextJobIndex = 1;
				JobHandle.ScheduleBatchedJobs();
			}
			m_Jobs[m_NextJobIndex++] = value;
		}

		public void CompleteJobs()
		{
			if (m_NextJobIndex > 0)
			{
				if (m_NextJobIndex > 1)
				{
					JobHandle.CombineDependencies(m_Jobs.Slice(0, m_NextJobIndex)).Complete();
				}
				else
				{
					m_Jobs[0].Complete();
				}
			}
			m_NextJobIndex = 0;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (!disposed)
			{
				if (disposing)
				{
					m_Jobs.Dispose();
				}
				disposed = true;
			}
		}
	}
