			if (flag7)
			{
				for (RenderData renderData2 = renderData.firstChild; renderData2 != null; renderData2 = renderData2.nextSibling)
				{
					DepthFirstOnClippingChanged(renderTreeManager, renderData, renderData2, dirtyID, hierarchical, isRootOfChange: false, isPendingHierarchicalRepaint, flag8, flag9, device, ref stats);
				}
			}
		}

		private static void DepthFirstOnOpacityChanged(RenderTreeManager renderTreeManager, float parentCompositeOpacity, RenderData renderData, uint dirtyID, bool hierarchical, ref ChainBuilderStats stats, bool isDoingFullVertexRegeneration = false)
		{
			if (dirtyID == renderData.dirtyID)
			{
				return;
			}
			renderData.dirtyID = dirtyID;
			if (renderData.isSubTreeQuad)
			{
				return;
			}
			stats.recursiveOpacityUpdatesExpanded++;
			float compositeOpacity = renderData.compositeOpacity;
			float num = renderData.owner.resolvedStyle.opacity * parentCompositeOpacity;
			bool flag = (compositeOpacity < VisibilityTreshold) ^ (num < VisibilityTreshold);
			bool flag2 = Mathf.Abs(compositeOpacity - num) > 0.0001f || flag;
			if (flag2)
			{
				renderData.compositeOpacity = num;
			}
			bool flag3 = false;
			if (num < parentCompositeOpacity - 0.0001f)
			{
				if (renderData.opacityID.ownedState == OwnedState.Inherited)
				{
					flag3 = true;
					renderData.opacityID = renderTreeManager.shaderInfoAllocator.AllocOpacity();
				}
				if ((flag3 || flag2) && renderData.opacityID.IsValid())
				{
					renderTreeManager.shaderInfoAllocator.SetOpacityValue(renderData.opacityID, num);
				}
			}
			else if (renderData.opacityID.ownedState == OwnedState.Inherited)
			{
				if (renderData.parent != null && !renderData.opacityID.Equals(renderData.parent.opacityID))
				{
					flag3 = true;
					renderData.opacityID = renderData.parent.opacityID;
					renderData.opacityID.ownedState = OwnedState.Inherited;
				}
			}
			else if (flag2 && renderData.opacityID.IsValid())
			{
				renderTreeManager.shaderInfoAllocator.SetOpacityValue(renderData.opacityID, num);
			}
			if ((renderData.dirtiedValues & RenderDataDirtyTypes.VisualsHierarchy) != RenderDataDirtyTypes.None)
			{
				isDoingFullVertexRegeneration = true;
			}
			if (!isDoingFullVertexRegeneration && flag3 && (renderData.dirtiedValues & RenderDataDirtyTypes.Visuals) == 0 && (renderData.headMesh != null || renderData.tailMesh != null))
			{
				renderData.renderTree.OnRenderDataOpacityIdChanged(renderData);
			}
			if (flag2 || flag3 || hierarchical)
			{
				for (RenderData renderData2 = renderData.firstChild; renderData2 != null; renderData2 = renderData2.nextSibling)
				{
					DepthFirstOnOpacityChanged(renderTreeManager, num, renderData2, dirtyID, hierarchical, ref stats, isDoingFullVertexRegeneration);
				}
			}
		}

		private static void OnColorChanged(RenderTreeManager renderTreeManager, RenderData renderData, uint dirtyID, ref ChainBuilderStats stats)
		{
			if (dirtyID == renderData.dirtyID)
			{
				return;
			}
			renderData.dirtyID = dirtyID;
			if (renderData.isSubTreeQuad)
			{
				return;
			}
			stats.colorUpdatesExpanded++;
			Color backgroundColor = renderData.owner.resolvedStyle.backgroundColor;
			if (renderData.backgroundAlpha == 0f && backgroundColor.a > 0f)
			{
				renderData.renderTree.OnRenderDataVisualsChanged(renderData, hierarchical: false);
			}
			renderData.backgroundAlpha = backgroundColor.a;
			bool flag = false;
			if ((renderData.owner.renderHints & RenderHints.DynamicColor) == RenderHints.DynamicColor && !renderData.isIgnoringDynamicColorHint)
			{
				if (InitColorIDs(renderTreeManager, renderData.owner))
				{
					flag = true;
				}
				SetColorValues(renderTreeManager, renderData.owner);
				if (renderData.owner is TextElement && !UpdateTextCoreSettings(renderTreeManager, renderData.owner))
				{
					flag = true;
				}
			}
			else
			{
				flag = true;
			}
			if (flag)
			{
				renderData.renderTree.OnRenderDataVisualsChanged(renderData, hierarchical: false);
			}
		}

		private static void DepthFirstOnTransformOrSizeChanged(RenderTreeManager renderTreeManager, RenderData renderData, uint dirtyID, UIRenderDevice device, bool isAncestorOfChangeSkinned, bool transformChanged, ref ChainBuilderStats stats)
		{
			if (dirtyID == renderData.dirtyID)
			{
				return;
			}
			stats.recursiveTransformUpdatesExpanded++;
			renderData.flags |= RenderDataFlags.IsClippingRectDirty;
			transformChanged |= (renderData.dirtiedValues & RenderDataDirtyTypes.Transform) != 0;
			if (RenderData.AllocatesID(renderData.clipRectID))
			{
				Debug.Assert(!renderData.isSubTreeQuad);
				renderTreeManager.shaderInfoAllocator.SetClipRectValue(renderData.clipRectID, GetClipRectIDClipInfo(renderData));
			}
			if (transformChanged)
			{
				if (UpdateLocalFlipsWinding(renderData))
				{
					renderData.renderTree.OnRenderDataVisualsChanged(renderData, hierarchical: true);
				}
				UpdateZeroScaling(renderData);
			}
			bool flag = true;
			if (RenderData.AllocatesID(renderData.transformID))
			{
				Debug.Assert(!renderData.isNestedRenderTreeRoot);
				renderTreeManager.shaderInfoAllocator.SetTransformValue(renderData.transformID, GetTransformIDTransformInfo(renderData));
				isAncestorOfChangeSkinned = true;
				stats.boneTransformed++;
			}
			else if (transformChanged)
			{
				if (renderData.isGroupTransform)
				{
					stats.groupTransformElementsChanged++;
				}
				else if (isAncestorOfChangeSkinned)
				{
					Debug.Assert(RenderData.InheritsID(renderData.transformID));
					flag = false;
					stats.skipTransformed++;
				}
				else if ((renderData.dirtiedValues & (RenderDataDirtyTypes.Visuals | RenderDataDirtyTypes.VisualsHierarchy)) == 0 && (renderData.headMesh != null || renderData.tailMesh != null))
				{
					if (NudgeVerticesToNewSpace(renderData, renderTreeManager, device))
					{
						stats.nudgeTransformed++;
					}
					else
					{
						renderData.renderTree.OnRenderDataVisualsChanged(renderData, hierarchical: false);
						stats.visualUpdateTransformed++;
					}
				}
			}
			if (flag)
			{
				renderData.dirtyID = dirtyID;
			}
			if (renderTreeManager.drawInCameras)
			{
				renderData.owner.EnsureWorldTransformAndClipUpToDate();
			}
			if (!renderData.isGroupTransform)
			{
				for (RenderData renderData2 = renderData.firstChild; renderData2 != null; renderData2 = renderData2.nextSibling)
				{
					DepthFirstOnTransformOrSizeChanged(renderTreeManager, renderData2, dirtyID, device, isAncestorOfChangeSkinned, transformChanged, ref stats);
				}
			}
		}

		public static bool UpdateTextCoreSettings(RenderTreeManager renderTreeManager, VisualElement ve)
		{
			if (ve == null || !TextUtilities.IsFontAssigned(ve))
			{
				return false;
			}
			bool flag = RenderData.AllocatesID(ve.renderData.textCoreSettingsID);
			TextCoreSettings textCoreSettingsForElement = TextUtilities.GetTextCoreSettingsForElement(ve, ignoreColors: false);
			if (!NeedsColorID(ve) && !NeedsTextCoreSettings(ve) && !flag)
			{
				ve.renderData.textCoreSettingsID = UIRVEShaderInfoAllocator.defaultTextCoreSettings;
				return true;
			}
			if (!flag)
			{
				ve.renderData.textCoreSettingsID = renderTreeManager.shaderInfoAllocator.AllocTextCoreSettings(textCoreSettingsForElement);
			}
			if (RenderData.AllocatesID(ve.renderData.textCoreSettingsID))
			{
				if (ve.panel.contextType == ContextType.Editor)
				{
					Color playModeTintColor = ve.playModeTintColor;
					textCoreSettingsForElement.faceColor *= playModeTintColor;
					textCoreSettingsForElement.outlineColor *= playModeTintColor;
					textCoreSettingsForElement.underlayColor *= playModeTintColor;
				}
				renderTreeManager.shaderInfoAllocator.SetTextCoreSettingValue(ve.renderData.textCoreSettingsID, textCoreSettingsForElement);
			}
			return true;
		}

		private static bool NudgeVerticesToNewSpace(RenderData renderData, RenderTreeManager renderTreeManager, UIRenderDevice device)
		{
			UIRUtility.GetVerticesTransformInfo(renderData, out var transform);
			Matrix4x4 matrix4x = transform * renderData.verticesSpace.inverse;
			Matrix4x4 matrix4x2 = matrix4x * renderData.verticesSpace;
			float num = Mathf.Abs(transform.m00 - matrix4x2.m00);
			num += Mathf.Abs(transform.m01 - matrix4x2.m01);
			num += Mathf.Abs(transform.m02 - matrix4x2.m02);
			num += Mathf.Abs(transform.m03 - matrix4x2.m03);
			num += Mathf.Abs(transform.m10 - matrix4x2.m10);
			num += Mathf.Abs(transform.m11 - matrix4x2.m11);
			num += Mathf.Abs(transform.m12 - matrix4x2.m12);
			num += Mathf.Abs(transform.m13 - matrix4x2.m13);
			num += Mathf.Abs(transform.m20 - matrix4x2.m20);
			num += Mathf.Abs(transform.m21 - matrix4x2.m21);
			num += Mathf.Abs(transform.m22 - matrix4x2.m22);
			num += Mathf.Abs(transform.m23 - matrix4x2.m23);
			if (num > 0.0001f)
			{
				return false;
			}
			renderData.verticesSpace = transform;
			NudgeJobData job = new NudgeJobData
			{
				transform = matrix4x
			};
			if (renderData.headMesh != null)
			{
				PrepareNudgeVertices(device, renderData.headMesh, out job.headSrc, out job.headDst, out job.headCount);
			}
			if (renderData.tailMesh != null)
			{
				PrepareNudgeVertices(device, renderData.tailMesh, out job.tailSrc, out job.tailDst, out job.tailCount);
			}
			renderTreeManager.jobManager.Add(ref job);
			if (renderData.hasExtraMeshes)
			{
				ExtraRenderData orAddExtraData = renderTreeManager.GetOrAddExtraData(renderData);
				for (BasicNode<MeshHandle> basicNode = orAddExtraData.extraMesh; basicNode != null; basicNode = basicNode.next)
				{
					NudgeJobData job2 = new NudgeJobData
					{
						transform = job.transform
					};
					PrepareNudgeVertices(device, basicNode.data, out job2.headSrc, out job2.headDst, out job2.headCount);
					renderTreeManager.jobManager.Add(ref job2);
				}
			}
			return true;
		}

		private unsafe static void PrepareNudgeVertices(UIRenderDevice device, MeshHandle mesh, out IntPtr src, out IntPtr dst, out int count)
		{
			int size = (int)mesh.allocVerts.size;
			NativeSlice<Vertex> nativeSlice = mesh.allocPage.vertices.cpuData.Slice((int)mesh.allocVerts.start, size);
			device.Update(mesh, (uint)size, out var vertexData);
			src = (IntPtr)nativeSlice.GetUnsafePtr();
			dst = (IntPtr)vertexData.GetUnsafePtr();
			count = size;
		}

		private static ClipMethod DetermineSelfClipMethod(RenderTreeManager renderTreeManager, RenderData renderData)
		{
			if (renderData.isSubTreeQuad)
			{
				return ClipMethod.NotClipped;
			}
			if (!renderData.owner.ShouldClip())
			{
				return ClipMethod.NotClipped;
			}
			if (renderTreeManager.drawInCameras)
			{
				return ClipMethod.ShaderDiscard;
			}
			ClipMethod result = ((renderData.isGroupTransform || (renderData.owner.renderHints & RenderHints.ClipWithScissors) != RenderHints.None) ? ClipMethod.Scissor : ClipMethod.ShaderDiscard);
			if (!renderTreeManager.elementBuilder.RequiresStencilMask(renderData.owner))
			{
				return result;
			}
			int num = 0;
			RenderData parent = renderData.parent;
			if (parent != null)
			{
				num = parent.childrenMaskDepth;
			}
			if (num == 7)
			{
				return result;
			}
			return ClipMethod.Stencil;
		}

		private static bool UpdateLocalFlipsWinding(RenderData renderData)
		{
			if (!renderData.owner.elementPanel.isFlat)
			{
				return false;
			}
			bool flag = false;
			if (!renderData.isNestedRenderTreeRoot)
			{
				Vector3 value = renderData.owner.resolvedStyle.scale.value;
				float num = value.x * value.y;
				if (Math.Abs(num) < 0.001f)
				{
					return false;
				}
				flag = num < 0f;
			}
			bool localFlipsWinding = renderData.localFlipsWinding;
			if (localFlipsWinding != flag)
			{
				renderData.localFlipsWinding = flag;
				return true;
			}
			return false;
		}

		private static void UpdateZeroScaling(RenderData renderData)
		{
			if (!renderData.isNestedRenderTreeRoot)
			{
				VisualElement owner = renderData.owner;
				bool flag = Math.Abs(owner.resolvedStyle.scale.value.x * owner.resolvedStyle.scale.value.y) < 0.001f;
				bool flag2 = false;
				VisualElement parent = owner.hierarchy.parent;
				if (parent != null)
				{
					flag2 = parent.renderData.worldTransformScaleZero;
				}
				renderData.worldTransformScaleZero = flag2 || flag;
			}
		}

		private static bool NeedsTransformID(VisualElement ve)
		{
			return !ve.renderData.isGroupTransform && (ve.renderHints & RenderHints.BoneTransform) != 0;
		}

		private static bool TransformIDHasChanged(Alloc before, Alloc after)
		{
			if (before.size == 0 && after.size == 0)
			{
				return false;
			}
			if (before.size != after.size || before.start != after.start)
			{
				return true;
			}
			return false;
		}

		internal static bool NeedsColorID(VisualElement ve)
		{
			return (ve.renderHints & RenderHints.DynamicColor) == RenderHints.DynamicColor;
		}

		internal static bool NeedsTextCoreSettings(VisualElement ve)
		{
			TextCoreSettings textCoreSettingsForElement = TextUtilities.GetTextCoreSettingsForElement(ve, ignoreColors: true);
			if (textCoreSettingsForElement.outlineWidth != 0f || textCoreSettingsForElement.underlayOffset != Vector2.zero || textCoreSettingsForElement.underlaySoftness != 0f)
			{
				return true;
			}
			return false;
		}

		private static bool InitColorIDs(RenderTreeManager renderTreeManager, VisualElement ve)
		{
			IResolvedStyle resolvedStyle = ve.resolvedStyle;
			bool result = false;
			if (!ve.renderData.colorID.IsValid() && ve is TextElement)
			{
				ve.renderData.colorID = renderTreeManager.shaderInfoAllocator.AllocColor();
				result = true;
			}
			if (!ve.renderData.backgroundColorID.IsValid())
			{
				ve.renderData.backgroundColorID = renderTreeManager.shaderInfoAllocator.AllocColor();
				result = true;
			}
			if (!ve.renderData.borderLeftColorID.IsValid() && resolvedStyle.borderLeftWidth > 0f)
			{
				ve.renderData.borderLeftColorID = renderTreeManager.shaderInfoAllocator.AllocColor();
				result = true;
			}
			if (!ve.renderData.borderTopColorID.IsValid() && resolvedStyle.borderTopWidth > 0f)
			{
				ve.renderData.borderTopColorID = renderTreeManager.shaderInfoAllocator.AllocColor();
				result = true;
			}
			if (!ve.renderData.borderRightColorID.IsValid() && resolvedStyle.borderRightWidth > 0f)
			{
				ve.renderData.borderRightColorID = renderTreeManager.shaderInfoAllocator.AllocColor();
				result = true;
			}
			if (!ve.renderData.borderBottomColorID.IsValid() && resolvedStyle.borderBottomWidth > 0f)
			{
				ve.renderData.borderBottomColorID = renderTreeManager.shaderInfoAllocator.AllocColor();
				result = true;
			}
			if (!ve.renderData.tintColorID.IsValid())
			{
				ve.renderData.tintColorID = renderTreeManager.shaderInfoAllocator.AllocColor();
				result = true;
			}
			return result;
		}

		private static void ResetColorIDs(VisualElement ve)
		{
			ve.renderData.colorID = BMPAlloc.Invalid;
			ve.renderData.backgroundColorID = BMPAlloc.Invalid;
			ve.renderData.borderLeftColorID = BMPAlloc.Invalid;
			ve.renderData.borderTopColorID = BMPAlloc.Invalid;
			ve.renderData.borderRightColorID = BMPAlloc.Invalid;
			ve.renderData.borderBottomColorID = BMPAlloc.Invalid;
			ve.renderData.tintColorID = BMPAlloc.Invalid;
		}

		public static void SetColorValues(RenderTreeManager renderTreeManager, VisualElement ve)
		{
			IResolvedStyle resolvedStyle = ve.resolvedStyle;
			if (ve.renderData.colorID.IsValid())
			{
				renderTreeManager.shaderInfoAllocator.SetColorValue(ve.renderData.colorID, resolvedStyle.color);
			}
			if (ve.renderData.backgroundColorID.IsValid())
			{
				renderTreeManager.shaderInfoAllocator.SetColorValue(ve.renderData.backgroundColorID, resolvedStyle.backgroundColor);
			}
			if (ve.renderData.borderLeftColorID.IsValid())
			{
				renderTreeManager.shaderInfoAllocator.SetColorValue(ve.renderData.borderLeftColorID, resolvedStyle.borderLeftColor);
			}
			if (ve.renderData.borderTopColorID.IsValid())
			{
				renderTreeManager.shaderInfoAllocator.SetColorValue(ve.renderData.borderTopColorID, resolvedStyle.borderTopColor);
			}
			if (ve.renderData.borderRightColorID.IsValid())
			{
				renderTreeManager.shaderInfoAllocator.SetColorValue(ve.renderData.borderRightColorID, resolvedStyle.borderRightColor);
			}
			if (ve.renderData.borderBottomColorID.IsValid())
			{
				renderTreeManager.shaderInfoAllocator.SetColorValue(ve.renderData.borderBottomColorID, resolvedStyle.borderBottomColor);
			}
			if (ve.renderData.tintColorID.IsValid())
			{
				renderTreeManager.shaderInfoAllocator.SetColorValue(ve.renderData.tintColorID, resolvedStyle.unityBackgroundImageTintColor);
			}
		}
	}
	internal struct DepthOrderedDirtyTracking
	{
		public RenderTree owner;

		public List<RenderData> heads;

		public List<RenderData> tails;

		public int[] minDepths;

		public int[] maxDepths;

		public uint dirtyID;

		public void EnsureFits(int maxDepth)
		{
			while (heads.Count <= maxDepth)
			{
				heads.Add(null);
				tails.Add(null);
			}
		}

		public void RegisterDirty(RenderData renderData, RenderDataDirtyTypes dirtyTypes, RenderDataDirtyTypeClasses dirtyTypeClass)
		{
			Debug.Assert(renderData.renderTree == owner);
			Debug.Assert(dirtyTypes != RenderDataDirtyTypes.None);
			int depthInRenderTree = renderData.depthInRenderTree;
			minDepths[(int)dirtyTypeClass] = ((depthInRenderTree < minDepths[(int)dirtyTypeClass]) ? depthInRenderTree : minDepths[(int)dirtyTypeClass]);
			maxDepths[(int)dirtyTypeClass] = ((depthInRenderTree > maxDepths[(int)dirtyTypeClass]) ? depthInRenderTree : maxDepths[(int)dirtyTypeClass]);
			if (renderData.dirtiedValues != RenderDataDirtyTypes.None)
			{
				renderData.dirtiedValues |= dirtyTypes;
				return;
			}
			renderData.dirtiedValues = dirtyTypes;
			if (tails[depthInRenderTree] != null)
			{
				tails[depthInRenderTree].nextDirty = renderData;
				renderData.prevDirty = tails[depthInRenderTree];
				tails[depthInRenderTree] = renderData;
			}
			else
			{
				List<RenderData> list = heads;
				RenderData value = (tails[depthInRenderTree] = renderData);
				list[depthInRenderTree] = value;
			}
		}

		public void ClearDirty(RenderData renderData, RenderDataDirtyTypes dirtyTypesInverse)
		{
			Debug.Assert(renderData.dirtiedValues != RenderDataDirtyTypes.None);
			renderData.dirtiedValues &= dirtyTypesInverse;
			if (renderData.dirtiedValues == RenderDataDirtyTypes.None)
			{
				if (renderData.prevDirty != null)
				{
					renderData.prevDirty.nextDirty = renderData.nextDirty;
				}
				if (renderData.nextDirty != null)
				{
					renderData.nextDirty.prevDirty = renderData.prevDirty;
				}
				if (tails[renderData.depthInRenderTree] == renderData)
				{
					Debug.Assert(renderData.nextDirty == null);
					tails[renderData.depthInRenderTree] = renderData.prevDirty;
				}
				if (heads[renderData.depthInRenderTree] == renderData)
				{
					Debug.Assert(renderData.prevDirty == null);
					heads[renderData.depthInRenderTree] = renderData.nextDirty;
				}
				renderData.prevDirty = (renderData.nextDirty = null);
			}
		}

		public void Reset()
		{
			for (int i = 0; i < minDepths.Length; i++)
			{
				minDepths[i] = int.MaxValue;
				maxDepths[i] = int.MinValue;
			}
		}
	}
	internal class RenderTree
	{
		[Flags]
		internal enum AllowedClasses
		{
			Clipping = 1,
			Opacity = 2,
			Color = 4,
			TransformSize = 8,
			Visuals = 0x10,
			All = 0x1F
		}

		private RenderTreeManager m_RenderTreeManager;

		private DepthOrderedDirtyTracking m_DirtyTracker;

		private RenderChainCommand m_FirstCommand;

		private RenderData m_RootRenderData;

		public TextureId quadTextureId;

		public RectInt quadRect;

		internal RenderTree parent;

		internal RenderTree firstChild;

		internal RenderTree nextSibling;

		private static readonly ProfilerMarker k_MarkerClipProcessing = new ProfilerMarker("RenderTree.UpdateClips");

		private static readonly ProfilerMarker k_MarkerOpacityProcessing = new ProfilerMarker("RenderTree.UpdateOpacity");

		private static readonly ProfilerMarker k_MarkerColorsProcessing = new ProfilerMarker("RenderTree.UpdateColors");

		private static readonly ProfilerMarker k_MarkerTransformProcessing = new ProfilerMarker("RenderTree.UpdateTransforms");

		private static readonly ProfilerMarker k_MarkerVisualsProcessing = new ProfilerMarker("RenderTree.UpdateVisuals");

		private AllowedClasses m_AllowedDirtyClasses = AllowedClasses.All;

		internal RenderTreeManager renderTreeManager => m_RenderTreeManager;

		internal RenderData rootRenderData => m_RootRenderData;

		internal ref DepthOrderedDirtyTracking dirtyTracker => ref m_DirtyTracker;

		internal RenderChainCommand firstCommand => m_FirstCommand;

		internal bool isRootRenderTree
		{
			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			get
			{
				return rootRenderData.owner.parent == null && !rootRenderData.isNestedRenderTreeRoot;
			}
		}

		public void Init(RenderTreeManager renderTreeManager, RenderData rootRenderData)
		{
			m_RenderTreeManager = renderTreeManager;
			m_RootRenderData = rootRenderData;
			m_DirtyTracker.owner = this;
			quadTextureId = TextureId.invalid;
			parent = null;
			firstChild = null;
			nextSibling = null;
			m_DirtyTracker.heads = new List<RenderData>(8);
			m_DirtyTracker.tails = new List<RenderData>(8);
			m_DirtyTracker.minDepths = new int[5];
			m_DirtyTracker.maxDepths = new int[5];
			m_DirtyTracker.Reset();
		}

		public void Reset()
		{
			m_RenderTreeManager = null;
			m_RootRenderData = null;
			parent = null;
			firstChild = null;
			nextSibling = null;
		}

		public void Dispose()
		{
			if (m_RootRenderData != null)
			{
				DepthFirstResetTextures(m_RootRenderData);
			}
		}

		private void DepthFirstResetTextures(RenderData renderData)
		{
			m_RenderTreeManager.ResetTextures(renderData);
			for (RenderData renderData2 = renderData.firstChild; renderData2 != null; renderData2 = renderData2.nextSibling)
			{
				DepthFirstResetTextures(renderData2);
			}
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void OnRenderDataClippingChanged(RenderData renderData, bool hierarchical)
		{
			Debug.Assert((m_AllowedDirtyClasses & AllowedClasses.Clipping) != 0);
			m_DirtyTracker.RegisterDirty(renderData, (RenderDataDirtyTypes)(4 | (hierarchical ? 8 : 0)), RenderDataDirtyTypeClasses.Clipping);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void OnRenderDataOpacityChanged(RenderData renderData, bool hierarchical = false)
		{
			Debug.Assert((m_AllowedDirtyClasses & AllowedClasses.Opacity) != 0);
			m_DirtyTracker.RegisterDirty(renderData, (RenderDataDirtyTypes)(0x80 | (hierarchical ? 256 : 0)), RenderDataDirtyTypeClasses.Opacity);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void OnRenderDataColorChanged(RenderData renderData)
		{
			Debug.Assert((m_AllowedDirtyClasses & AllowedClasses.Color) != 0);
			m_DirtyTracker.RegisterDirty(renderData, RenderDataDirtyTypes.Color, RenderDataDirtyTypeClasses.Color);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void OnRenderDataTransformOrSizeChanged(RenderData renderData, bool transformChanged, bool clipRectSizeChanged)
		{
			Debug.Assert((m_AllowedDirtyClasses & AllowedClasses.TransformSize) != 0);
			RenderDataDirtyTypes dirtyTypes = (RenderDataDirtyTypes)((transformChanged ? 1 : 0) | (clipRectSizeChanged ? 2 : 0));
			m_DirtyTracker.RegisterDirty(renderData, dirtyTypes, RenderDataDirtyTypeClasses.TransformSize);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void OnRenderDataOpacityIdChanged(RenderData renderData)
		{
			Debug.Assert((m_AllowedDirtyClasses & AllowedClasses.Visuals) != 0);
			m_DirtyTracker.RegisterDirty(renderData, RenderDataDirtyTypes.VisualsOpacityId, RenderDataDirtyTypeClasses.Visuals);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void OnRenderDataVisualsChanged(RenderData renderData, bool hierarchical)
		{
			Debug.Assert((m_AllowedDirtyClasses & AllowedClasses.Visuals) != 0);
			m_DirtyTracker.RegisterDirty(renderData, (RenderDataDirtyTypes)(0x10 | (hierarchical ? 32 : 0)), RenderDataDirtyTypeClasses.Visuals);
		}

		public void ProcessChanges(ref ChainBuilderStats stats)
		{
			m_DirtyTracker.dirtyID++;
			int num = 0;
			RenderDataDirtyTypes renderDataDirtyTypes = RenderDataDirtyTypes.Clipping | RenderDataDirtyTypes.ClippingHierarchy;
			RenderDataDirtyTypes dirtyTypesInverse = ~renderDataDirtyTypes;
			m_AllowedDirtyClasses &= ~AllowedClasses.Clipping;
			for (int i = m_DirtyTracker.minDepths[num]; i <= m_DirtyTracker.maxDepths[num]; i++)
			{
				RenderData renderData = m_DirtyTracker.heads[i];
				while (renderData != null)
				{
					RenderData nextDirty = renderData.nextDirty;
					if ((renderData.dirtiedValues & renderDataDirtyTypes) != RenderDataDirtyTypes.None)
					{
						if (renderData.dirtyID != m_DirtyTracker.dirtyID)
						{
							RenderEvents.ProcessOnClippingChanged(m_RenderTreeManager, renderData, m_DirtyTracker.dirtyID, ref stats);
						}
						m_DirtyTracker.ClearDirty(renderData, dirtyTypesInverse);
					}
					renderData = nextDirty;
					stats.dirtyProcessed++;
				}
			}
			m_DirtyTracker.dirtyID++;
			num = 1;
			renderDataDirtyTypes = RenderDataDirtyTypes.Opacity | RenderDataDirtyTypes.OpacityHierarchy;
			dirtyTypesInverse = ~renderDataDirtyTypes;
			m_AllowedDirtyClasses &= ~AllowedClasses.Opacity;
			for (int j = m_DirtyTracker.minDepths[num]; j <= m_DirtyTracker.maxDepths[num]; j++)
			{
				RenderData renderData2 = m_DirtyTracker.heads[j];
				while (renderData2 != null)
				{
					RenderData nextDirty2 = renderData2.nextDirty;
					if ((renderData2.dirtiedValues & renderDataDirtyTypes) != RenderDataDirtyTypes.None)
					{
						if (renderData2.dirtyID != m_DirtyTracker.dirtyID)
						{
							RenderEvents.ProcessOnOpacityChanged(m_RenderTreeManager, renderData2, m_DirtyTracker.dirtyID, ref stats);
						}
						m_DirtyTracker.ClearDirty(renderData2, dirtyTypesInverse);
					}
					renderData2 = nextDirty2;
					stats.dirtyProcessed++;
				}
			}
			m_DirtyTracker.dirtyID++;
			num = 2;
			renderDataDirtyTypes = RenderDataDirtyTypes.Color;
			dirtyTypesInverse = ~renderDataDirtyTypes;
			m_AllowedDirtyClasses &= ~AllowedClasses.Color;
			for (int k = m_DirtyTracker.minDepths[num]; k <= m_DirtyTracker.maxDepths[num]; k++)
			{
				RenderData renderData3 = m_DirtyTracker.heads[k];
				while (renderData3 != null)
				{
					RenderData nextDirty3 = renderData3.nextDirty;
					if ((renderData3.dirtiedValues & renderDataDirtyTypes) != RenderDataDirtyTypes.None)
					{
						if (renderData3 != null && renderData3.dirtyID != m_DirtyTracker.dirtyID)
						{
							RenderEvents.ProcessOnColorChanged(m_RenderTreeManager, renderData3, m_DirtyTracker.dirtyID, ref stats);
						}
						m_DirtyTracker.ClearDirty(renderData3, dirtyTypesInverse);
					}
					renderData3 = nextDirty3;
					stats.dirtyProcessed++;
				}
			}
			m_DirtyTracker.dirtyID++;
			num = 3;
			renderDataDirtyTypes = RenderDataDirtyTypes.Transform | RenderDataDirtyTypes.ClipRectSize;
			dirtyTypesInverse = ~renderDataDirtyTypes;
			m_AllowedDirtyClasses &= ~AllowedClasses.TransformSize;
			for (int l = m_DirtyTracker.minDepths[num]; l <= m_DirtyTracker.maxDepths[num]; l++)
			{
				RenderData renderData4 = m_DirtyTracker.heads[l];
				while (renderData4 != null)
				{
					RenderData nextDirty4 = renderData4.nextDirty;
					if ((renderData4.dirtiedValues & renderDataDirtyTypes) != RenderDataDirtyTypes.None)
					{
						if (renderData4.dirtyID != m_DirtyTracker.dirtyID)
						{
							RenderEvents.ProcessOnTransformOrSizeChanged(m_RenderTreeManager, renderData4, m_DirtyTracker.dirtyID, ref stats);
						}
						m_DirtyTracker.ClearDirty(renderData4, dirtyTypesInverse);
					}
					renderData4 = nextDirty4;
					stats.dirtyProcessed++;
				}
			}
			m_RenderTreeManager.jobManager.CompleteNudgeJobs();
			m_DirtyTracker.dirtyID++;
			num = 4;
			renderDataDirtyTypes = RenderDataDirtyTypes.AllVisuals;
			dirtyTypesInverse = ~renderDataDirtyTypes;
			m_AllowedDirtyClasses &= ~AllowedClasses.Visuals;
			for (int m = m_DirtyTracker.minDepths[num]; m <= m_DirtyTracker.maxDepths[num]; m++)
			{
				RenderData renderData5 = m_DirtyTracker.heads[m];
				while (renderData5 != null)
				{
					RenderData nextDirty5 = renderData5.nextDirty;
					if ((renderData5.dirtiedValues & renderDataDirtyTypes) != RenderDataDirtyTypes.None)
					{
						if (renderData5.dirtyID != m_DirtyTracker.dirtyID)
						{
							m_RenderTreeManager.visualChangesProcessor.ProcessOnVisualsChanged(renderData5, m_DirtyTracker.dirtyID, ref stats);
						}
						m_DirtyTracker.ClearDirty(renderData5, dirtyTypesInverse);
					}
					renderData5 = nextDirty5;
					stats.dirtyProcessed++;
				}
			}
			m_RenderTreeManager.meshGenerationDeferrer.ProcessDeferredWork(m_RenderTreeManager.visualChangesProcessor.meshGenerationContext);
			m_RenderTreeManager.visualChangesProcessor.ScheduleMeshGenerationJobs();
			m_RenderTreeManager.meshGenerationDeferrer.ProcessDeferredWork(m_RenderTreeManager.visualChangesProcessor.meshGenerationContext);
			m_RenderTreeManager.visualChangesProcessor.ConvertEntriesToCommands(ref stats);
			m_RenderTreeManager.jobManager.CompleteConvertMeshJobs();
			m_RenderTreeManager.jobManager.CompleteCopyMeshJobs();
			m_RenderTreeManager.opacityIdAccelerator.CompleteJobs();
			m_DirtyTracker.Reset();
			m_AllowedDirtyClasses = AllowedClasses.All;
		}

		internal void OnRenderCommandAdded(RenderChainCommand command)
		{
			if (command.prev == null)
			{
				m_FirstCommand = command;
			}
		}

		internal void OnRenderCommandsRemoved(RenderChainCommand firstCommand, RenderChainCommand lastCommand)
		{
			if (firstCommand.prev == null)
			{
				m_FirstCommand = lastCommand.next;
			}
		}

		internal void ChildWillBeRemoved(RenderData renderData)
		{
			if (renderData.dirtiedValues != RenderDataDirtyTypes.None)
			{
				m_DirtyTracker.ClearDirty(renderData, ~renderData.dirtiedValues);
			}
			Debug.Assert(renderData.dirtiedValues == RenderDataDirtyTypes.None);
			Debug.Assert(renderData.prevDirty == null);
			Debug.Assert(renderData.nextDirty == null);
		}
	}
	internal class RenderTreeCompositor : IDisposable
	{
		private enum DrawOperationType
		{
			Undefined,
			RenderTree,
			Effect
		}

		private class DrawOperation
		{
			private DrawOperationType m_Type;

			private VisualElement m_VisualElement;

			private RenderTree m_RenderTree;

			private PostProcessingPass m_Effect;

			private FilterFunction m_Filter;

			public RectInt bounds;

			public RectInt drawSourceBounds;

			public Vector4 drawSourceTexOffsets;

			public RenderTexture dstTexture;

			public TextureId dstTextureId;

			public DrawOperation parent;

			public DrawOperation firstChild;

			public DrawOperation lastChild;

			public DrawOperation prevSibling;

			public DrawOperation nextSibling;

			public DrawOperationType type => m_Type;

			public VisualElement visualElement => m_VisualElement;

			public RenderTree renderTree => m_RenderTree;

			public PostProcessingPass effect => m_Effect;

			public FilterFunction filter => m_Filter;

			public void Init(VisualElement ve, in PostProcessingPass effect, FilterFunction filter)
			{
				m_Type = DrawOperationType.Effect;
				m_VisualElement = ve;
				m_Effect = effect;
				m_Filter = filter;
				m_RenderTree = ve.nestedRenderData.renderTree;
				InitPointers();
			}

			public void Init(RenderTree renderTree)
			{
				m_Type = DrawOperationType.RenderTree;
				m_VisualElement = renderTree.rootRenderData.owner;
				m_RenderTree = renderTree;
				InitPointers();
			}

			private void InitPointers()
			{
				parent = null;
				firstChild = null;
				lastChild = null;
				prevSibling = null;
				nextSibling = null;
			}

			public void Reset()
			{
				m_Type = DrawOperationType.Undefined;
				m_VisualElement = null;
				m_RenderTree = null;
				m_Effect = default(PostProcessingPass);
				m_Filter = default(FilterFunction);
				dstTexture = null;
				dstTextureId = TextureId.invalid;
			}

			public void AddChild(DrawOperation op)
			{
				Debug.Assert(op.prevSibling == null);
				op.parent = this;
				op.nextSibling = firstChild;
				if (firstChild != null)
				{
					firstChild.prevSibling = op;
				}
				firstChild = op;
			}
		}

		private readonly RenderTreeManager m_RenderTreeManager;

		private DrawOperation m_RootOperation;

		private List<RenderTexture> m_AllocatedRenderTextures = new List<RenderTexture>();

		private MaterialPropertyBlock m_Block = new MaterialPropertyBlock();

		private ObjectPool<DrawOperation> m_DrawOperationPool = new ObjectPool<DrawOperation>(() => new DrawOperation());

		protected bool disposed { get; private set; }

		public RenderTreeCompositor(RenderTreeManager owner)
		{
			m_RenderTreeManager = owner;
		}

		public void Update(RenderTree rootRenderTree)
		{
			CleanupOperationTree();
			if (rootRenderTree != null)
			{
				BuildDrawOperationTree(rootRenderTree);
				UpdateDrawBounds_PostOrder(m_RootOperation);
				AssignTextureIds_DepthFirst(m_RootOperation);
			}
		}

		private void BuildDrawOperationTree(RenderTree rootRenderTree)
		{
			m_RootOperation = m_DrawOperationPool.Get();
			m_RootOperation.Init(rootRenderTree);
		}

		private static PostProcessingMargins GetReadMargins(PostProcessingPass effect, FilterFunction func)
		{
			if (effect.computeRequiredReadMarginsCallback != null)
			{
				return effect.computeRequiredReadMarginsCallback(func);
			}
			return effect.readMargins;
		}

		private static PostProcessingMargins GetWriteMargins(PostProcessingPass effect, FilterFunction func)
		{
			if (effect.computeRequiredWriteMarginsCallback != null)
			{
				return effect.computeRequiredWriteMarginsCallback(func);
			}
			return effect.writeMargins;
		}

		private static void UpdateDrawBounds_PostOrder(DrawOperation op)
		{
			Rect? rect = null;
			switch (op.type)
			{
			case DrawOperationType.Effect:
			{
				DrawOperation firstChild = op.firstChild;
				if (firstChild != null)
				{
					Debug.Assert(firstChild.nextSibling == null);
					UpdateDrawBounds_PostOrder(firstChild);
					if (UIRUtility.RectHasArea(op.drawSourceBounds))
					{
						rect = UIRUtility.CastToRect(op.drawSourceBounds);
					}
				}
				break;
			}
			case DrawOperationType.RenderTree:
			{
				for (DrawOperation drawOperation = op.firstChild; drawOperation != null; drawOperation = drawOperation.nextSibling)
				{
					UpdateDrawBounds_PostOrder(drawOperation);
					if (UIRUtility.RectHasArea(drawOperation.bounds))
					{
						UIRUtility.ComputeMatrixRelativeToRenderTree(drawOperation.visualElement.renderData, out var transform);
						Rect rect2 = VisualElement.CalculateConservativeRect(ref transform, UIRUtility.CastToRect(drawOperation.bounds));
						rect = ((!rect.HasValue) ? rect2 : UIRUtility.Encapsulate(rect.Value, rect2));
					}
				}
				Rect boundingBox = op.renderTree.rootRenderData.owner.boundingBox;
				if (UIRUtility.RectHasArea(boundingBox))
				{
					rect = ((!rect.HasValue) ? boundingBox : UIRUtility.Encapsulate(rect.Value, boundingBox));
				}
				else
				{
					Debug.Assert(!rect.HasValue);
				}
				break;
			}
			default:
				throw new NotImplementedException();
			}
			if (rect.HasValue)
			{
				Rect value = rect.Value;
				PostProcessingMargins margins = default(PostProcessingMargins);
				PostProcessingMargins margins2 = default(PostProcessingMargins);
				DrawOperation parent = op.parent;
				RectInt bounds;
				if (parent != null && parent.type == DrawOperationType.Effect)
				{
					margins = GetReadMargins(parent.effect, parent.filter);
					margins2 = GetWriteMargins(parent.effect, parent.filter);
					Rect rect3 = UIRUtility.InflateByMargins(UIRUtility.InflateByMargins(value, margins), margins2);
					bounds = UIRUtility.CastToRectInt(rect3);
				}
				else
				{
					bounds = UIRUtility.CastToRectInt(value);
				}
				DrawOperation parent2 = op.parent;
				if (parent2 != null && parent2.type == DrawOperationType.Effect)
				{
					Rect r = value;
					r = UIRUtility.InflateByMargins(r, margins2);
					op.parent.drawSourceBounds = UIRUtility.CastToRectInt(r);
					Vector4 drawSourceTexOffsets = new Vector4(margins.left, margins.top, margins.right, margins.bottom);
					if (bounds.width > 0 && bounds.height > 0)
					{
						float num = 1f / (float)bounds.width;
						float num2 = 1f / (float)bounds.height;
						drawSourceTexOffsets.x *= num;
						drawSourceTexOffsets.y *= num2;
						drawSourceTexOffsets.z *= num;
						drawSourceTexOffsets.w *= num2;
					}
					else
					{
						drawSourceTexOffsets = Vector4.zero;
					}
					op.parent.drawSourceTexOffsets = drawSourceTexOffsets;
				}
				op.bounds = bounds;
			}
			else
			{
				op.bounds = RectInt.zero;
			}
			DrawOperation parent3 = op.parent;
			if (parent3 != null && parent3.type == DrawOperationType.RenderTree)
			{
				op.renderTree.quadRect = op.bounds;
			}
		}

		private void AssignTextureIds_DepthFirst(DrawOperation op)
		{
			DrawOperation parent = op.parent;
			if (parent != null && parent.type == DrawOperationType.RenderTree)
			{
				Debug.Assert(!op.renderTree.quadTextureId.IsValid());
				TextureId quadTextureId = (op.dstTextureId = m_RenderTreeManager.textureRegistry.AllocAndAcquireDynamic());
				op.renderTree.quadTextureId = quadTextureId;
				op.parent.renderTree.OnRenderDataVisualsChanged(op.visualElement.renderData, hierarchical: false);
			}
			else
			{
				Debug.Assert(!op.dstTextureId.IsValid());
			}
			for (DrawOperation drawOperation = op.firstChild; drawOperation != null; drawOperation = drawOperation.nextSibling)
			{
				AssignTextureIds_DepthFirst(drawOperation);
			}
		}

		public void RenderNestedPasses()
		{
			ExecuteDrawOperation_PostOrder(m_RootOperation);
		}

		private void ExecuteDrawOperation_PostOrder(DrawOperation op)
		{
			for (DrawOperation drawOperation = op.firstChild; drawOperation != null; drawOperation = drawOperation.nextSibling)
			{
				ExecuteDrawOperation_PostOrder(drawOperation);
			}
			if (op.parent == null)
			{
				return;
			}
			RectInt bounds = op.bounds;
			if (bounds.width <= 0)
			{
				return;
			}
			Debug.Assert(bounds.height > 0);
			GraphicsFormat colorFormat = ((QualitySettings.activeColorSpace == ColorSpace.Linear) ? GraphicsFormat.R8G8B8A8_SRGB : GraphicsFormat.R8G8B8A8_UNorm);
			RenderTextureDescriptor desc = new RenderTextureDescriptor(bounds.width, bounds.height, colorFormat, GraphicsFormat.D24_UNorm_S8_UInt);
			op.dstTexture = RenderTexture.GetTemporary(desc);
			m_AllocatedRenderTextures.Add(op.dstTexture);
			if (op.dstTextureId.IsValid())
			{
				m_RenderTreeManager.textureRegistry.UpdateDynamic(op.dstTextureId, op.dstTexture);
			}
			switch (op.type)
			{
			case DrawOperationType.Effect:
				try
				{
					RenderTexture active = RenderTexture.active;
					RenderTexture.active = op.dstTexture;
					GL.Clear(clearDepth: false, clearColor: true, Color.clear);
					op.effect.material.SetPass(op.effect.passIndex);
					m_Block.SetTexture("_MainTex", op.firstChild.dstTexture);
					if (op.effect.prepareMaterialPropertyBlockCallback != null)
					{
						op.effect.prepareMaterialPropertyBlockCallback(m_Block, op.filter);
					}
					else
					{
						ApplyEffectParameters(op.effect, op.filter, op.visualElement);
					}
					Utility.SetPropertyBlock(m_Block);
					Matrix4x4 mat = ProjectionUtils.Ortho(bounds.xMin, bounds.xMax, bounds.yMax, bounds.yMin, 0f, 1f);
					GL.LoadProjectionMatrix(mat);
					GL.modelview = Matrix4x4.identity;
					RectInt drawSourceBounds = op.drawSourceBounds;
					Vector4 drawSourceTexOffsets = op.drawSourceTexOffsets;
					GL.Viewport(new Rect(0f, 0f, bounds.width, bounds.height));
					GL.Begin(7);
					GL.TexCoord2(drawSourceTexOffsets.x, drawSourceTexOffsets.w);
					GL.Vertex3(drawSourceBounds.xMin, drawSourceBounds.yMax, 0.5f);
					GL.TexCoord2(drawSourceTexOffsets.x, 1f - drawSourceTexOffsets.y);
					GL.Vertex3(drawSourceBounds.xMin, drawSourceBounds.yMin, 0.5f);
					GL.TexCoord2(1f - drawSourceTexOffsets.z, 1f - drawSourceTexOffsets.y);
					GL.Vertex3(drawSourceBounds.xMax, drawSourceBounds.yMin, 0.5f);
					GL.TexCoord2(1f - drawSourceTexOffsets.z, drawSourceTexOffsets.w);
					GL.Vertex3(drawSourceBounds.xMax, drawSourceBounds.yMax, 0.5f);
					GL.End();
					RenderTexture.active = active;
					break;
				}
				catch
				{
					break;
				}
			case DrawOperationType.RenderTree:
				m_RenderTreeManager.RenderSingleTree(op.renderTree, op.dstTexture, bounds);
				break;
			default:
				throw new NotImplementedException();
			}
		}

		private void ApplyEffectParameters(PostProcessingPass effect, FilterFunction filter, VisualElement source)
		{
			if (effect.parameterBindings == null)
			{
				return;
			}
			FixedBuffer4<FilterParameter> parameters = filter.parameters;
			int parameterCount = filter.parameterCount;
			for (int i = 0; i < effect.parameterBindings.Length && i < parameterCount; i++)
			{
				ParameterBinding parameterBinding = effect.parameterBindings[i];
				FilterParameter filterParameter = parameters[i];
				if (filterParameter.type == FilterParameterType.Float)
				{
					m_Block.SetFloat(parameterBinding.name, filterParameter.floatValue);
				}
				else if (filterParameter.type == FilterParameterType.Color)
				{
					m_Block.SetColor(parameterBinding.name, filterParameter.colorValue);
				}
			}
		}

		private void CleanupOperationTree()
		{
			if (m_RootOperation != null)
			{
				CleanupOperation_PostOrder(m_RootOperation);
				m_RootOperation = null;
			}
			for (int i = 0; i < m_AllocatedRenderTextures.Count; i++)
			{
				RenderTexture.ReleaseTemporary(m_AllocatedRenderTextures[i]);
			}
			m_AllocatedRenderTextures.Clear();
		}

		private void CleanupOperation_PostOrder(DrawOperation op)
		{
			for (DrawOperation drawOperation = op.firstChild; drawOperation != null; drawOperation = drawOperation.nextSibling)
			{
				CleanupOperation_PostOrder(drawOperation);
			}
			if (op.dstTextureId.IsValid())
			{
				m_RenderTreeManager.textureRegistry.Release(op.dstTextureId);
				op.dstTextureId = TextureId.invalid;
				op.renderTree.quadTextureId = TextureId.invalid;
			}
			op.Reset();
			m_DrawOperationPool.Release(op);
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected void Dispose(bool disposing)
		{
			if (!disposed)
			{
				if (disposing)
				{
					CleanupOperationTree();
				}
				disposed = true;
			}
		}
	}
