	internal static class Shaders
	{
		public static readonly string k_AtlasBlit = "Hidden/Internal-UIRAtlasBlitCopy";

		public static readonly string k_Default = "Hidden/Internal-UIRDefault";

		public static readonly string k_RuntimeGaussianBlur = "Hidden/UIR/GaussianBlur";

		public static readonly string k_RuntimeColorEffect = "Hidden/UIR/ColorEffect";

		public static readonly string k_ColorConversionBlit = "Hidden/Internal-UIE-ColorConversionBlit";

		public static readonly string k_ForceGammaKeyword = "UIE_FORCE_GAMMA";

		private static Material s_DefaultMaterial;

		private static int s_RefCount;

		public static Material defaultMaterial => GetOrCreateMaterial(ref s_DefaultMaterial, k_Default);

		private static Material GetOrCreateMaterial(ref Material material, string shaderName)
		{
			if (material == null)
			{
				Shader shader = Shader.Find(shaderName);
				if (shader == null)
				{
					Debug.LogError("Could not find shader '" + shaderName + "'");
					return null;
				}
				material = new Material(shader);
				material.hideFlags = HideFlags.DontSave;
			}
			return material;
		}

		public static void Acquire()
		{
			s_RefCount++;
		}

		public static void Release()
		{
			s_RefCount--;
			Debug.Assert(s_RefCount >= 0, "UIR materials acquire/release don't match.");
			if (s_RefCount < 1)
			{
				s_RefCount = 0;
				UIRUtility.Destroy(s_DefaultMaterial);
				s_DefaultMaterial = null;
			}
		}
	}
	internal class TempAllocator<T> : IDisposable where T : struct
	{
		private struct Page
		{
			public NativeArray<T> array;

			public int used;
		}

		public struct Statistics
		{
			public PageStatistics pool;

			public PageStatistics[] excess;
		}

		public struct PageStatistics
		{
			public int size;

			public int used;
		}

		private readonly int m_ExcessMinCapacity;

		private readonly int m_ExcessMaxCapacity;

		private Page m_Pool;

		private List<Page> m_Excess;

		private int m_NextExcessSize;

		protected bool disposed { get; private set; }

		public TempAllocator(int poolCapacity, int excessMinCapacity, int excessMaxCapacity)
		{
			Debug.Assert(poolCapacity >= 1);
			Debug.Assert(excessMinCapacity >= 1);
			Debug.Assert(excessMinCapacity <= excessMaxCapacity);
			m_ExcessMinCapacity = excessMinCapacity;
			m_ExcessMaxCapacity = excessMaxCapacity;
			m_NextExcessSize = m_ExcessMinCapacity;
			m_Pool = default(Page);
			m_Pool.array = new NativeArray<T>(poolCapacity, Allocator.Persistent, NativeArrayOptions.UninitializedMemory);
			m_Excess = new List<Page>(8);
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected void Dispose(bool disposing)
		{
			if (!disposed)
			{
				if (disposing)
				{
					Reset();
					m_Pool.array.Dispose();
					m_Pool.used = 0;
				}
				disposed = true;
			}
		}

		public NativeSlice<T> Alloc(int count)
		{
			if (count > 0)
			{
				return DoAlloc(count);
			}
			return default(NativeSlice<T>);
		}

		private NativeSlice<T> DoAlloc(int count)
		{
			Debug.Assert(!disposed);
			int num = m_Pool.used + count;
			if (num <= m_Pool.array.Length)
			{
				NativeSlice<T> result = m_Pool.array.Slice(m_Pool.used, count);
				m_Pool.used = num;
				return result;
			}
			if (count > m_ExcessMaxCapacity)
			{
				Page item = new Page
				{
					array = new NativeArray<T>(count, Allocator.TempJob, NativeArrayOptions.UninitializedMemory),
					used = count
				};
				m_Excess.Add(item);
				return item.array.Slice(0, count);
			}
			for (int num2 = m_Excess.Count - 1; num2 >= 0; num2--)
			{
				Page value = m_Excess[num2];
				num = value.used + count;
				if (num <= value.array.Length)
				{
					NativeSlice<T> result2 = value.array.Slice(value.used, count);
					value.used = num;
					m_Excess[num2] = value;
					return result2;
				}
			}
			while (count > m_NextExcessSize)
			{
				m_NextExcessSize <<= 1;
			}
			Page item2 = new Page
			{
				array = new NativeArray<T>(m_NextExcessSize, Allocator.TempJob, NativeArrayOptions.UninitializedMemory),
				used = count
			};
			m_Excess.Add(item2);
			m_NextExcessSize = Mathf.Min(m_NextExcessSize << 1, m_ExcessMaxCapacity);
			return item2.array.Slice(0, count);
		}

		public void Reset()
		{
			ReleaseExcess();
			m_Pool.used = 0;
			m_NextExcessSize = m_ExcessMinCapacity;
		}

		private void ReleaseExcess()
		{
			foreach (Page item in m_Excess)
			{
				item.array.Dispose();
			}
			m_Excess.Clear();
		}

		public Statistics GatherStatistics()
		{
			Statistics result = new Statistics
			{
				pool = new PageStatistics
				{
					size = m_Pool.array.Length,
					used = m_Pool.used
				},
				excess = new PageStatistics[m_Excess.Count]
			};
			for (int i = 0; i < m_Excess.Count; i++)
			{
				result.excess[i] = new PageStatistics
				{
					size = m_Excess[i].array.Length,
					used = m_Excess[i].used
				};
			}
			return result;
		}
	}
	internal class TempMeshAllocatorImpl : IDisposable
	{
		private struct ThreadData
		{
			public List<IntPtr> allocations;
		}

		private GCHandle m_GCHandle;

		private ThreadData[] m_ThreadData;

		private TempAllocator<Vertex> m_VertexPool = new TempAllocator<Vertex>(8192, 2048, 65536);

		private TempAllocator<ushort> m_IndexPool = new TempAllocator<ushort>(16384, 4096, 131072);

		protected bool disposed { get; private set; }

		public TempMeshAllocatorImpl()
		{
			m_GCHandle = GCHandle.Alloc(this);
			m_ThreadData = new ThreadData[JobsUtility.ThreadIndexCount];
			for (int i = 0; i < JobsUtility.ThreadIndexCount; i++)
			{
				m_ThreadData[i].allocations = new List<IntPtr>();
			}
		}

		public void CreateNativeHandle(out TempMeshAllocator allocator)
		{
			TempMeshAllocator.Create(m_GCHandle, out allocator);
		}

		private unsafe NativeSlice<T> Allocate<T>(int count, int alignment) where T : struct
		{
			ref ThreadData reference = ref m_ThreadData[UIRUtility.GetThreadIndex()];
			Debug.Assert(count > 0);
			long size = UnsafeUtility.SizeOf<T>() * count;
			void* ptr = UnsafeUtility.Malloc(size, UnsafeUtility.AlignOf<T>(), Allocator.TempJob);
			reference.allocations.Add((IntPtr)ptr);
			NativeArray<T> nativeArray = NativeArrayUnsafeUtility.ConvertExistingDataToNativeArray<T>(ptr, count, Allocator.Invalid);
			return nativeArray;
		}

		public void AllocateTempMesh(int vertexCount, int indexCount, out NativeSlice<Vertex> vertices, out NativeSlice<ushort> indices)
		{
			if (vertexCount > UIRenderDevice.maxVerticesPerPage)
			{
				throw new ArgumentOutOfRangeException("vertexCount", $"Attempting to allocate {vertexCount} vertices which exceeds the limit of {UIRenderDevice.maxVerticesPerPage}.");
			}
			if (!JobsUtility.IsExecutingJob)
			{
				if (disposed)
				{
					DisposeHelper.NotifyDisposedUsed(this);
					vertices = default(NativeSlice<Vertex>);
					indices = default(NativeSlice<ushort>);
				}
				else
				{
					vertices = ((vertexCount > 0) ? m_VertexPool.Alloc(vertexCount) : default(NativeSlice<Vertex>));
					indices = ((indexCount > 0) ? m_IndexPool.Alloc(indexCount) : default(NativeSlice<ushort>));
				}
			}
			else
			{
				vertices = ((vertexCount > 0) ? Allocate<Vertex>(vertexCount, 4) : default(NativeSlice<Vertex>));
				indices = ((indexCount > 0) ? Allocate<ushort>(indexCount, 2) : default(NativeSlice<ushort>));
			}
		}

		public unsafe void Clear()
		{
			for (int i = 0; i < m_ThreadData.Length; i++)
			{
				foreach (IntPtr allocation in m_ThreadData[i].allocations)
				{
					UnsafeUtility.Free(allocation.ToPointer(), Allocator.TempJob);
				}
				m_ThreadData[i].allocations.Clear();
			}
			m_VertexPool.Reset();
			m_IndexPool.Reset();
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected void Dispose(bool disposing)
		{
			if (!disposed)
			{
				if (disposing)
				{
					Clear();
					m_GCHandle.Free();
					m_VertexPool.Dispose();
					m_IndexPool.Dispose();
				}
				disposed = true;
			}
		}
	}
