		public void RemoveAt(int index)
		{
			ref LayoutNodeData nodeData = ref m_Access.GetNodeData(m_Handle);
			Assert.IsTrue(nodeData.Children.IsCreated);
			if ((uint)index >= nodeData.Children.Count)
			{
